-- canonical domains.
-- ============================================================

INSERT INTO tools (
  name, slug, tagline, description, website_url,
  pricing_type, pricing_details, skill_level, has_api, platforms,
  features, integrations, is_published,
  best_for, not_for, editorial_verdict,
  tutorial_urls, limitations, models, community_links, use_cases, our_views,
  last_verified_at
) VALUES
('Cresta', 'cresta', 'Real-time AI agent assist plus conversation intelligence for enterprise contact centers.', 'Cresta is a contact-center AI platform built for sales and customer-experience teams at enterprise scale. The core product is a layered stack: real-time Agent Assist that whispers next-best actions and approved language to a live agent mid-call, a Knowledge Agent that surfaces grounded answers from internal documentation, an autonomous AI Agent for full deflection, and a Conversation Intelligence layer that mines every interaction for coaching signals, win-loss patterns, and quality scores.

Where Gong and Chorus focus on post-call analytics for B2B sales reps, Cresta focuses on in-call intervention for high-volume operations — airlines, telco, BPOs, large insurance and lending desks. Its differentiator is the proprietary Cresta-tuned models trained on a customer''s own conversation corpus, so the suggestions reflect the playbook the team actually wants reps to follow rather than generic large-model output.

Customers include United, Alaska Airlines, Marriott, Hilton, LendingClub, and Propel Holdings. Deployments are typically multi-quarter — the platform sits inside the contact-center stack alongside Genesys, NICE, or Five9, and integrates with the CRM (Salesforce, MS Dynamics) plus internal knowledge sources.

This is firmly an enterprise tool. There is no self-serve tier, pricing is six-figure-and-up annually, and rollout requires conversation data, change-management buy-in, and ongoing model tuning. For organizations that have those resources, the real-time intervention is materially different from after-the-fact call review — and it''s the part of the AI-coaching market that traditional call-recording vendors haven''t cracked.', 'https://cresta.com', 'paid', '[{"plan":"Enterprise","price":"Custom","features":["Real-time Agent Assist","Conversation Intelligence","Knowledge Agent","Autonomous AI Agent","Custom-tuned models on customer corpus","Quality management + coaching analytics","CCaaS + CRM integrations"]}]'::jsonb, 'intermediate', true, '{"web","api"}', '{"Real-time Agent Assist with whisper prompts","Cresta Knowledge Agent grounded in internal docs","Autonomous AI Agent for deflection","Conversation Intelligence + signal mining","Custom-tuned models on customer conversation corpus","AI quality management + auto-scorecards","Coaching analytics with rep-level skill maps","Post-call wrap-up automation","Sentiment + intent detection","CCaaS integrations (Genesys, NICE, Five9)","CRM integrations (Salesforce, MS Dynamics)"}', '{"Salesforce","Microsoft Dynamics","Genesys","NICE CXone","Five9","Amazon Connect","Twilio","Zendesk","ServiceNow","Snowflake"}', true, '{"Enterprise contact centers running >100 agents","Inbound sales + service teams needing in-call coaching","Regulated industries (financial services, telco, airlines)","Operations leaders prioritizing real-time intervention over post-call review"}', '{"SMB sales teams (no self-serve tier and pricing starts mid-six-figures)","Pure outbound SDR motions (Gong/Clari/Nooks fit better)","Teams without dedicated CCaaS infrastructure","Buyers who need pricing transparency upfront"}', 'The strongest real-time agent-assist platform in the enterprise contact-center category — but only worth evaluating if you already operate a CCaaS-grade contact center and have the data + change-management muscle for a multi-quarter rollout.', '{"https://cresta.com/resources/"}', 'Sales-gated pricing with six-figure floor — no transparency for SMB buyers. English-first; non-English language coverage exists but is uneven. Custom model tuning requires substantial conversation data (typically months of recordings) before suggestion quality matures. Real-time accuracy varies by domain — highly scripted flows perform best, complex consultative sales worst. Salesforce + Genesys integrations are deepest; smaller CCaaS stacks may need more services work.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Whisper next-best actions to live agents during inbound sales calls.","Auto-score 100% of customer service calls instead of QA-sampling 2%.","Surface grounded knowledge-base answers without rep manually searching the wiki.","Detect compliance risk language in regulated lending or insurance conversations in real time.","Identify objection patterns across millions of calls to update the playbook quarterly."}', 'Sweet spot: a Fortune-1000 contact center with >200 agents, a clear playbook the team wants enforced, and an operations leader who has authority to drive a multi-quarter AI rollout. At that scale, the real-time intervention layer pays back via shorter handle time, higher conversion, and offloaded QA — and Cresta''s custom-tuned models genuinely outperform generic LLM wrappers because they''ve been fitted to your own corpus.

Failure modes to know about. First, expectations: Cresta is not a magic install — model quality climbs over months as the system ingests your conversation data, and teams that expect ChatGPT-style results in week one will be disappointed. Second, change management eats deployments alive: agents resist whisper prompts unless coaching, incentives, and QA are aligned around using them. Third, integration depth varies — Salesforce + Genesys customers get a smooth path; teams on niche or homegrown CCaaS stacks should budget significant services time. Fourth, real-time AI hallucination risk is real on knowledge-grounded answers; treat the Knowledge Agent as a first-draft tool with human verification, not a source of truth.

What to pilot before committing. Run a 90-day pilot on one queue (ideally inbound sales, where intervention has the clearest revenue signal). Measure handle time, conversion rate, QA score variance, and rep adoption of suggestions — that last one is the leading indicator. If reps voluntarily use suggestions >40% of the time and conversion moves >5%, the technology is working in your environment. If adoption stays under 20%, the issue is almost always change management, not the AI — fix that before scaling.', now()),
('Nooks', 'nooks', 'AI parallel dialer plus virtual sales floor for outbound SDR teams.', 'Nooks is the workspace outbound SDRs use to actually run their day. The flagship feature is the AI Dialer — a parallel dialing engine that places multiple calls simultaneously, drops voicemails, filters out answering machines, and connects the rep only when a human picks up. The pitch is connect-rate math: in a market where cold-call answer rates have collapsed under 2%, parallel dialing is the only way to get a rep into more live conversations per hour without hiring more reps.

Around the dialer Nooks layers AI features that the SDR motion needs: AI Coach scores calls and flags coachable moments, AI Researcher pulls live account intelligence before the dial, AI Roleplay lets reps practice objection handling against a simulated buyer, and AI Sequencing personalizes outbound emails and LinkedIn messages. The "salesfloor" experience adds shared-room voice presence so distributed SDR teams can hear each other working — an emotional driver that solo dialers miss.

The competitive frame: Orum and ConnectAndSell are the established parallel dialers, but they''re narrow point tools. Aircall is a phone system, not a sales engine. Outreach and Salesloft own the cadence layer but don''t do live calling well. Nooks bundles the parallel dialer, the cadence layer, the coaching layer, and the salesfloor into one workspace — that consolidation is the bet, and it''s why the platform shows up in HubSpot, Greenhouse, and Modern Health stacks.

Pricing is sales-gated and not cheap — typical deployments run several thousand dollars per seat per year — so this is a tool for teams whose outbound math depends on call volume per rep, not a side experiment.', 'https://nooks.ai', 'paid', '[{"plan":"Custom","price":"Custom","features":["AI Parallel Dialer","AI Coach + scorecards","AI Researcher + waterfall enrichment","AI Roleplay simulator","AI Sequencing (multi-channel cadences)","Virtual salesfloor","Spam protection + caller-ID rotation","CRM sync (Salesforce, HubSpot)"]}]'::jsonb, 'intermediate', true, '{"web","api"}', '{"AI Parallel Dialer (3x connect rate claim)","AI Coach with call scoring + coachable moments","AI Researcher with waterfall enrichment + buying intent","AI Roleplay simulator for objection practice","AI Sequencing for multi-channel cadences","Virtual salesfloor with shared voice presence","Auto voicemail drop","Answering-machine detection","Spam-likely caller-ID rotation","Local presence dialing","Salesforce + HubSpot bidirectional sync","Slack notifications + connect alerts"}', '{"Salesforce","HubSpot","Outreach","Salesloft","Gong","ZoomInfo","Apollo","LinkedIn Sales Navigator","Slack","Google Calendar","Microsoft 365"}', true, '{"Outbound SDR + BDR teams ≥10 reps","High-velocity sales motions where call volume drives pipeline","Distributed teams that have lost the in-office salesfloor energy","Sales leaders measuring connect rate as a primary KPI"}', '{"Account-executive teams running consultative deals (volume isn''t the bottleneck)","Solo founders making <50 calls/week","Teams with strict do-not-call compliance overhead (parallel dialing creates regulatory exposure in some regions)","Sales orgs without a working cadence + ICP — Nooks accelerates whatever motion you have"}', 'The most complete outbound-SDR workspace in 2026 if your sales motion is volume-driven. Parallel dialing alone justifies the cost; the coaching and salesfloor layers are what make the platform sticky.', '{"https://help.nooks.ai/"}', 'Sales-gated pricing — no transparent per-seat number on the site. Parallel dialing creates regulatory complexity (TCPA in the US, GDPR + national do-not-call lists in Europe) that legal teams should review before rollout. Spam-likely caller-ID flagging is an ongoing arms race; expect to rotate numbers and tolerate periodic dips. AI Coach accuracy on objection categorization is good but not perfect — treat scorecards as input to coaching, not the coaching itself. CRM sync is deepest with Salesforce and HubSpot; other CRMs need more setup work. English-first.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Triple SDR connect rates by parallel-dialing 4 numbers at once.","Auto-coach every dial without a manager listening live to 200 calls a week.","Run AI Roleplay sessions with new SDR hires before they touch real prospects.","Replace the lost in-office salesfloor energy for a distributed BDR team.","Detect buying-intent signals on accounts and route them to the right rep''s queue."}', 'Sweet spot: a 10–100 rep outbound SDR team where the bottleneck is genuinely conversations-per-rep-per-day, not lead quality or messaging. At that scale, the parallel dialer delivers a measurable connect-rate lift in week one, and the salesfloor + coaching layers compound over months. Teams that pair Nooks with a working ICP, a tested cadence, and active sales-management see the strongest returns.

Failure modes to watch. First, parallel dialing can mask a broken motion — if your messaging or list quality is the actual problem, more dials per hour just produces more rejection per hour. Diagnose before deploying. Second, regulatory exposure: TCPA suits and EU privacy complaints around parallel dialing are real, and "the vendor said it was fine" is not a legal defense. Have your compliance team read the disclosure flow before turning it on. Third, AI features have variance — coaching scorecards are helpful directionally but miscategorize tone and intent often enough that they shouldn''t replace human listening. Fourth, the salesfloor feature only works if reps actually keep mics open — adoption requires manager modeling.

What to pilot. Run a 30-day A/B with 5 reps on Nooks and 5 reps on your current dialer, same ICP, same cadence. Measure connects per hour, meetings booked per dial, and rep self-reported energy at end of day. The first metric will move; the second is the one that actually matters for ROI. If meetings-per-dial holds steady and connects per hour climbs, the math is real. If meetings-per-dial collapses, your messaging breaks at higher volume and Nooks isn''t the fix.', now()),
('Sybill', 'sybill-ai', 'AI deal intelligence and behavior analysis on sales calls — Magic Summaries, CRM autofill, and Ask Sybill.', 'Sybill is an AI sales assistant that sits on top of Zoom, Google Meet, and Microsoft Teams calls and turns them into structured deal intelligence. The flagship feature is the Magic Summary — a behavior-aware call summary that captures not just what was said but what was committed to, who pushed back, and what the next step is, then pushes that into the CRM and the rep''s follow-up email automatically.

The product expanded from call summaries into a full deal-workspace stack: Ask Sybill is a conversational interface that lets reps query across calls, emails, and CRM data ("show me every objection raised by Acme this quarter"), Deal Inspection flags pipeline risk and missing qualification, Pre-Meeting Briefs assemble the context the rep needs in the 5 minutes before a call, and CRM Autofill writes structured fields back to Salesforce or HubSpot without manual data entry.

Where Gong and Clari built call-recording platforms first and grew enterprise revenue-intelligence features on top, Sybill came up the other way — starting with the individual rep''s pain (CRM hygiene, follow-up emails, summary work) and growing into team-level deal intelligence. That''s why Sybill has a published self-serve plan ($36/seat for Pro, $108/seat for Business) where Gong and Clari are sales-gated. For a 5–50 rep team, Sybill is the tool you can buy and roll out without a procurement cycle.

The behavior-analysis claim is the differentiated piece — Sybill''s models score sentiment, engagement, and commitment language across speakers, not just transcribe. Whether that scoring meaningfully changes outcomes is rep-by-rep; the unambiguous win is hours saved on summaries and CRM data entry.', 'https://sybill.ai', 'subscription', '[{"plan":"Free","price":"$0","features":["500 credits/week","Unlimited recordings","20 AI meeting summaries/month (team)","10 Ask Sybill queries/week","3 months data storage"]},{"plan":"Pro","price":"$36/seat/month","features":["2,500 credits/week","Unlimited Magic Summaries","Ask Sybill across calls + emails + Slack","AI pre-meeting briefs","AI follow-up emails","Unlimited data storage"]},{"plan":"Business","price":"$108/seat/month","features":["Unlimited credits","Ask Sybill across deals (CRM)","Unlimited AI task automation","CRM Autofill (10 fields)","Custom Slack channels","Deal workspace","Admin controls"]},{"plan":"Enterprise","price":"Custom","features":["Unlimited CRM Autofill","API + MCP access","Custom integrations","Data migration","Dedicated CSM","Enhanced security + SLA"]}]'::jsonb, 'beginner', true, '{"web","api"}', '{"Magic Summary call summaries with behavior signals","Ask Sybill conversational deal queries","Deal Inspection + risk detection","Pre-Meeting Briefs","AI-generated follow-up emails","CRM Autofill (Salesforce + HubSpot)","Sentiment + engagement scoring per speaker","Coaching analytics + rep scorecards","Sales plays + competitor mention tracking","MCP API access (Enterprise)","Slack + email recap delivery"}', '{"Salesforce","HubSpot","Zoom","Google Meet","Microsoft Teams","Slack","Gmail","Outlook","Outreach","Salesloft","Pipedrive","Zoho CRM"}', true, '{"AEs and CSMs running consultative deals on Zoom/Meet/Teams","SMB-to-mid-market sales teams without Gong/Clari budget","Founders + revenue leaders who want CRM hygiene without nagging reps","Sales managers who need deal-level visibility without sitting through every call"}', '{"Pure outbound SDR teams (Nooks/Orum fit the dialing motion better)","Enterprise contact centers (Cresta/Gong Engage are the right tier)","Teams that don''t record calls (Sybill needs the recording to function)","Industries with strict recording-consent rules without legal review"}', 'The best summary-and-CRM-hygiene AI for a 5–50 rep team that doesn''t want to spend Gong money. Magic Summary plus CRM Autofill alone justify the Pro tier.', '{"https://help.sybill.ai/"}', 'Recording-consent rules vary by region — California, EU, and several other jurisdictions require dual-consent that reps and prospects must navigate. Sentiment + engagement scoring is directional, not gospel; treat it as a signal, not a verdict on a rep or a deal. AI summary hallucination risk exists — Sybill is good but occasionally invents commitments that weren''t made; spot-check before sending. Deepest CRM integration is with Salesforce and HubSpot; Pipedrive and Zoho work but with thinner field mapping. English-first; multilingual call coverage is improving but uneven.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Auto-generate a behavior-aware call summary and follow-up email after every Zoom demo.","Eliminate the 30 minutes/day each AE spends on CRM data entry.","Ask ''which deals slipped this month and why?'' across pipeline + call transcripts.","Surface every objection a competitor was mentioned in over the last quarter.","Give a sales manager deal-level visibility without listening to 40 calls a week."}', 'Sweet spot: a 5–50 rep B2B sales team running consultative deals on video calls, where reps already record calls and the bottleneck is summary work + CRM hygiene + follow-up speed. At Pro tier ($36/seat) the math is straightforward — if Sybill saves each rep 30 minutes a day, payback is immediate at any reasonable rep cost. The Business tier ($108/seat) is worth it once you want CRM Autofill writing structured fields and Ask Sybill operating across the full deal context.

Failure modes. First, Sybill''s summaries are excellent but not infallible — reps who blindly send the AI follow-up email occasionally misrepresent commitments and embarrass themselves. Build a 10-second review habit. Second, behavior scoring (sentiment, engagement) is interesting but rep coaching shouldn''t hinge on it; the signal is too noisy to use as a performance verdict. Third, recording consent is a legal question, not a UX one — get GC sign-off on the consent flow before rollout in regulated regions. Fourth, the deeper deal-intelligence features (Ask Sybill across CRM, Deal Inspection) only pay off once you''re recording most of pipeline; partial coverage produces partial signal.

What to pilot. Put 5 reps on Pro for 30 days, measure time saved on summaries + CRM, track follow-up email send rate, and survey reps on whether they''re actually opening the Magic Summary. If summary open-rate is >70% and CRM hygiene scores improve, scale up — and only step to Business once the team is asking for the CRM Autofill and Ask Sybill features unprompted.', now()),
('11x', '11x-ai', 'Autonomous AI digital workers — Alice the AI SDR and Julian the AI phone rep — running outbound for B2B teams.', '11x sells autonomous AI digital workers that take on the job titles of human revenue roles. The two flagship workers are Alice, an outbound AI SDR that prospects, researches, personalizes, and engages across email and LinkedIn to book meetings, and Julian, an inbound AI phone agent that answers calls, qualifies leads, and books on the rep''s calendar 24/7. The framing is deliberate: not "AI tools to help your SDRs" but "AI workers replacing the SDR seat."

Alice operates an end-to-end outbound motion — pulls signals (job changes, funding, intent), drafts personalized first-touch and follow-up emails, runs multi-step sequences, handles replies, and drops booked meetings into the rep''s calendar. Julian sits on inbound numbers, holds real voice conversations, qualifies against a custom rubric, and routes hot leads. Both workers are configured through a control panel — you set ICP, messaging guidelines, qualification criteria, and tools they can use; you don''t write prompts.

The competitive frame is important. Traditional outbound stacks combine an SDR ($85K+ fully loaded), a sales engagement tool (Outreach/Salesloft), an enrichment vendor (ZoomInfo/Apollo), and a dialer. 11x''s pitch is: collapse all of that into one autonomous worker at a fraction of the headcount cost. The trade is that you''re trusting an AI agent with brand-facing communication at volume — and the early-2025 controversy around 11x''s testimonials and customer-reported quality issues is the cautionary half of that story, not a settled question.

Pricing is sales-gated and per-worker — typical deployments are several thousand dollars per worker per month. For teams whose outbound is mature enough to articulate the messaging guardrails clearly, 11x removes a category of operational overhead. For teams hoping the AI will figure out the messaging itself, the output quality won''t justify the cost.', 'https://11x.ai', 'paid', '[{"plan":"Custom (per worker)","price":"Custom","features":["Alice — AI SDR (outbound email + LinkedIn)","Julian — AI phone agent (inbound voice)","Signal-driven prospecting","Multi-step personalized sequencing","Reply handling + meeting booking","ICP + messaging configuration","CRM sync (Salesforce, HubSpot)","Dedicated implementation"]}]'::jsonb, 'intermediate', true, '{"web","api"}', '{"Alice — autonomous outbound AI SDR","Julian — autonomous inbound AI phone agent","Signal-driven prospecting (job changes, funding, intent)","Personalized email + LinkedIn outbound","Multi-step sequences with reply handling","Inbound voice qualification + routing","ICP + qualification rubric configuration","Calendar booking automation","CRM bidirectional sync","Reporting + worker performance dashboards"}', '{"Salesforce","HubSpot","Outreach","Salesloft","ZoomInfo","Apollo","LinkedIn","Gmail","Outlook","Slack","Google Calendar"}', true, '{"Mid-market + enterprise B2B teams with mature outbound messaging","Sales orgs evaluating headcount-vs-AI tradeoffs at the SDR layer","Companies with high inbound call volume that goes unanswered nights/weekends","Founders + RevOps leaders willing to own AI-output review as part of the workflow"}', '{"Teams without a tested outbound playbook (the AI amplifies whatever motion you give it)","Brand-sensitive industries where any AI-driven misstep is reputational risk","Sales orgs that haven''t solved attribution + ICP definition first","Anyone expecting AI to replace strategic selling or complex enterprise pursuit"}', 'The most aggressive bet on AI replacing SDR seats — genuinely interesting if your outbound messaging is mature, genuinely risky if it isn''t. Pilot small, measure rigorously, and read the customer-reported quality controversies before signing.', '{"https://docs.11x.ai/"}', 'Sales-gated pricing with several-thousand-per-worker-per-month floor. Output quality has been publicly questioned by customers — 2025 reporting raised concerns about testimonial accuracy and message quality. AI hallucination + fabrication risk on outbound emails is real; the worker can invent context that doesn''t exist. English-first; multilingual coverage is limited. Voice agent (Julian) accuracy on accented speech is uneven. Salesforce + HubSpot integrations work; smaller CRMs require services time. Brand-safety review is a leadership-level decision, not an ops-level one.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Replace the SDR layer for top-of-funnel outbound to a defined ICP.","Cover inbound calls 24/7 with a voice agent that books qualified meetings.","Test whether autonomous AI can sustain meeting-booked rate at SDR-team scale.","Reduce headcount cost on a repeatable outbound motion that''s already working manually.","Run signal-driven outbound (job changes, funding) at higher cadence than human SDRs can sustain."}', 'Sweet spot: a mid-market or enterprise team whose outbound messaging is documented, tested, and producing meetings — and where leadership genuinely wants to test whether autonomous AI can sustain that motion at lower fully-loaded cost than a human SDR team. At that maturity, 11x is one of a small number of vendors with end-to-end autonomous-worker products that actually ship rather than demo.

Failure modes are significant and underweighted in most evaluations. First, output quality variance: AI-drafted outbound emails fabricate details, miss context, and occasionally embarrass the brand — the worker''s job description says "autonomous" but the operational reality requires human review of message samples until you trust the output, and many customers never get there. Second, there''s a documented controversy from 2024–2025 around customer testimonials and quality claims; do reference calls with current customers, not vendor-supplied references. Third, autonomous outbound at scale magnifies any flaws in your ICP or messaging — an SDR sends 50 bad emails before someone notices; an AI worker sends 5,000. Fourth, total cost of ownership is higher than the line-item — RevOps + sales-leadership review time is real and not free.

What to pilot. Constrain the test brutally — one ICP, one messaging guardrail set, one geographic region, 30 days, 200 sends/day max. Have a human review every outbound email for the first week before send goes live. Measure replies-per-send, positive-reply rate, meeting-booked rate, and brand complaints. Compare against your existing SDR baseline on the same ICP. If positive-reply rate matches or exceeds human SDRs and brand complaints stay near zero, scale up cautiously. If output quality requires constant human cleanup, the headcount-savings math collapses — and that''s the failure mode to take seriously.', now()),
('Second Nature', 'second-nature-ai', 'AI-powered sales role-play and coaching simulator with conversational AI avatars.', 'Second Nature is an AI sales-training platform built around a single core idea: reps learn faster by talking to an AI buyer than by reading a playbook or listening to recordings. The product runs realistic simulated conversations — a rep can practice a discovery call, an objection handling drill, a cold-call opener, or a customer-service scenario, and the AI buyer responds in real time, pushes back, asks follow-ups, and scores the rep against a rubric the team configured.

The core feature is the AI Conversation Simulator, paired with named AI avatars (configurable buyer personas with their own backstory, objections, and personality). Trainers can build custom scenarios from existing materials — sales decks, recorded customer calls, playbooks, training videos — and the platform turns those into role-play modules with measurable scorecards.

Where Highspot, MindTickle, and Allego built sales-enablement platforms around content + course delivery and bolted on coaching features, Second Nature is built coaching-first. The pitch is that watching a course doesn''t change rep behavior; rehearsing a real conversation with an AI buyer that pushes back does. For onboarding new SDRs and AEs, certifying reps on a new product launch, or running ongoing skill drills, the simulator format is genuinely different from the LMS-style alternative.

Pricing is sales-gated — there''s a free trial of role-plays but no public per-seat number — so this is a tool you evaluate via demo and pilot rather than buy off a price page. Customers report material reductions in time-to-quota for new hires, which is the metric that justifies the spend if it holds in your environment.', 'https://secondnature.ai', 'paid', '[{"plan":"Custom","price":"Custom","features":["AI Conversation Simulator","Named AI buyer avatars","Custom role-play scenarios","Auto-generated scorecards","Training-content ingestion (decks, calls, videos)","Manager dashboards","Certification programs","CRM + LMS integrations"]}]'::jsonb, 'intermediate', true, '{"web"}', '{"AI Conversation Simulator (real-time voice + text)","Named AI buyer avatars with configurable personas","Custom scenario builder","Auto-generated scorecards aligned to org rubric","Training content ingestion (decks, recorded calls, videos, playbooks)","Pre-built scenario library (discovery, cold call, objection handling, customer service)","Manager + admin dashboards","Certification + onboarding tracks","Rep-level skill maps","CRM + LMS integrations"}', '{"Salesforce","HubSpot","Microsoft Teams","Zoom","Workday","SAP SuccessFactors","Cornerstone","Docebo","Slack"}', true, '{"L&D + sales-enablement teams onboarding new hires","RevOps leaders measuring time-to-quota","Customer-service training teams","Companies launching new products that require rep certification","Sales managers who want practice volume without spending hours on role-plays themselves"}', '{"Solo founders or sub-10-person sales teams (the platform is built for ongoing programs, not occasional drills)","Teams without a defined skills rubric (the AI scorecard mirrors what you tell it to measure)","Pure self-study learners — Second Nature is most effective inside a manager-led coaching cadence","Buyers who need transparent per-seat pricing on the website"}', 'The most credible AI role-play platform for sales onboarding and certification — meaningfully different from LMS-style enablement tools because reps actually rehearse the conversation rather than watch a course.', '{"https://secondnature.ai/resources/"}', 'Sales-gated pricing — no public per-seat number. Scorecard accuracy is only as good as the rubric you upload; a vague rubric produces vague scoring. AI hallucination risk is lower than on summary-style products because the AI is generating buyer responses rather than asserting facts, but personas can occasionally drift off-script in long sessions. English-first; non-English avatars are limited. Voice quality is good but not indistinguishable from human — reps adapt within a session. Best-fit deployments require a manager-led coaching cadence; standalone "go practice on your own" usage produces low engagement.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Onboard 20 new SDRs in 30 days with daily simulator drills instead of shadow-listening.","Certify the entire field team on a new product launch before reps touch real customers.","Run weekly objection-handling drills against a rotating set of buyer personas.","Ramp customer-service reps on tough scenarios (escalation, refunds, churn) without burning real customer interactions.","Generate scorecards on rep readiness that managers can review before letting reps sell live."}', 'Sweet spot: a sales or customer-service org with ≥30 reps, a defined skills rubric, and a manager-led coaching cadence — typically a mid-market or enterprise L&D function that owns onboarding and product-launch certification. At that scale, replacing shadow-listening and live role-plays with on-demand AI simulator drills compresses ramp time materially, and the scorecard data feeds back into where coaching attention should go.

Failure modes. First, the platform mirrors the rubric you give it — if your skills framework is fuzzy, the AI scorecards will be fuzzy and managers will lose trust in them. Invest in the rubric before the rollout. Second, voluntary self-practice doesn''t happen at meaningful volume; deployments succeed when managers assign drills, review scores, and tie completion to certification. Third, persona realism is good but not perfect — reps notice the AI''s patterns within 5–10 sessions, and scenario libraries need refresh cadence to stay challenging. Fourth, integration with the LMS or CRM matters for adoption; standalone usage produces fragmented data.

What to pilot. Pick one cohort — a new-hire SDR class, a product-launch certification, or a problem-skill area like cold-call opening — and run Second Nature against your current training method for 60 days. Measure ramp time to first-meeting (or to first-quota-hit), manager-rated skill confidence, and rep-reported usefulness. If ramp time compresses by >20% and manager confidence is high, scale into the broader enablement program. If reps complete drills but ramp doesn''t move, the issue is either rubric quality or coaching follow-through, not the simulator itself.', now()),
('Robin AI', 'robin-ai', 'AI contract review, redlining, and drafting for in-house legal teams — London-based, Anthropic-partnered.', 'Robin AI is a London-headquartered legal-AI company that markets itself as a Legal Intelligence Platform for in-house legal teams. The product reads contracts, surfaces risks, redlines clauses against your firm''s playbook, drafts replacement language, and tracks the resulting obligations as a calendar of commitments. Where general-purpose AI assistants give you a chat window, Robin gives you a contract-aware workspace: a chat interface that knows what type of agreement is in front of it (NDA, MSA, DPA, employment agreement), an intelligent search layer that auto-detects signatures and key terms, and an obligations module that converts every "the supplier shall..." into a tracked checklist with smart alerts.

Against the broader market, Robin sits in a clearly defined slot. Spellbook is Word-add-in-first and aimed at outside-counsel transactional drafting. Ironclad AI is a CLM platform with AI bolted on top — the buyer is procurement / legal ops, the lift is enterprise. Harvey AI is the Big Law / elite firm play, priced and built for firm-wide deployment. Robin AI is the mid-market in-house pick: small-to-medium legal departments who do not want a full CLM rip-and-replace, want fast contract review on the documents they already have, and want a vendor whose roadmap is unambiguously about in-house teams rather than law firms.

The Anthropic relationship is central — Robin is featured by Anthropic as a partner, and the product is widely understood to be Claude-powered for its contract-review and drafting workloads. That matters because Claude''s longer context window and lower hallucination profile on long-document tasks line up well with reviewing 80-page agreements end-to-end without chunking artifacts. Robin claims roughly 80% faster review and over 500K documents processed across its customer base.

Pricing is sales-gated; there is no public per-seat number. The product is positioned for legal teams of roughly 5 to 100, sold via demo and proof-of-concept rather than self-serve checkout.', 'https://robinai.com', 'paid', '[{"plan":"Team","price":"Custom","features":["Contract review and redlining","Playbook-based clause checking","Obligations tracking","Workspace collaboration"]},{"plan":"Enterprise","price":"Custom","features":["SSO","Advanced security","Dedicated success manager","Custom playbooks and integrations"]}]'::jsonb, 'intermediate', false, '{"web"}', '{"AI contract review with playbook-based clause checking","AI redlining and replacement-language drafting","Contract-aware chat (knows NDA vs MSA vs DPA)","Intelligent search across executed contracts (auto-detects type, signatures, key terms)","Obligation extraction and tracked checklists with alerts","Workspace collaboration for in-house legal","Powered by Anthropic / Claude for long-document review","UK and EU data-residency options","SOC 2 / enterprise security posture"}', '{"Microsoft Word","Google Drive","SharePoint","Anthropic Claude"}', true, '{"In-house legal teams at 50–2,000-person companies","Legal ops leaders standardising contract playbooks","Commercial counsel reviewing recurring NDAs / MSAs / DPAs","UK and EU teams who want a regionally-headquartered vendor"}', '{"Big Law transactional groups (Harvey is purpose-built for that)","Solo practitioners and small firms (pricing is enterprise-scale)","Teams who need a full CLM with workflow / e-sign / repository (pick Ironclad)"}', 'The strongest mid-market in-house contract-AI pick in 2026, and the obvious choice if you want a Claude-powered review layer without committing to a full CLM replacement.', '{}', 'Like every legal LLM tool, hallucination risk is real on novel clause language — Mata v. Avianca is the cautionary tale every GC quotes back to vendors, and Robin''s guardrails do not eliminate the need for human sign-off on every output. Jurisdiction depth is strongest for English-language US / UK / EU commercial contracts; less battle-tested on Asia-Pacific or Latin American agreements. Pricing is sales-gated and out of reach for solo practitioners. Practice-management / matter-management integration is thinner than legacy CLM incumbents — if you need deep CRM, billing, or e-signature integration in one workflow, expect to glue it.', '{"Anthropic Claude"}', '{"reddit_threads":[]}'::jsonb, '{"Review and redline an inbound vendor MSA against your firm''s standard playbook in 10 minutes.","Extract every renewal date and price-escalation clause from a portfolio of 500 executed contracts.","Draft a counter-position on a limitation-of-liability clause grounded in the firm''s prior negotiated outcomes.","Run obligation tracking so commercial counsel never miss a notice deadline."}', 'Sweet spot: a 5–30-person in-house legal team that already lives in Word and SharePoint, processes a steady stream of inbound third-paper agreements, and wants the review-and-redline cycle to compress from days to hours without ripping out their CLM. Robin''s contract-aware chat plus playbook redlining is exactly the workflow these teams describe when asked what they wish ChatGPT did for them, and the Claude backend is well-matched to long-document review where hallucination cost is multi-million-dollar liability.

Failure modes to plan for. First, hallucination is not solved — Robin reduces but does not eliminate the risk that the model fabricates a clause reference or misstates governing law, and "the AI said so" is not a defense in any jurisdiction. Treat every output as an associate''s first draft, never as final. Second, jurisdiction bias: outputs reflect the training data, which skews US / UK / EU commercial. If you regularly negotiate under, say, Singapore or Brazilian law, pilot heavily before trusting clause-by-clause guidance. Third, the obligations module is only as good as your post-signature workflow — if commercial teams ignore the alerts, you have an expensive notification system.

What to pilot. Pick 20 real recently-executed contracts you already know cold. Run them through Robin''s review and redlining. Score every flag against what your team actually called out. Above ~80% agreement on material risks, the tool will save real lawyer time; below that and the playbook needs more tuning before you scale seats.', now()),
('EvenUp', 'evenup', 'AI for plaintiff personal-injury law firms — demand-letter generation, case valuation, and end-to-end PI workflow.', 'EvenUp is a vertical AI platform built specifically for plaintiff personal-injury law firms. The flagship workflow is AI demand-package generation: a paralegal uploads the medical records, bills, and incident documents, EvenUp''s system extracts the clinical narrative, builds the chronology, calculates damages, and drafts a full demand letter in the firm''s voice — work that historically takes a paralegal 10–20 hours per case. EvenUp also ships intake automation that scores incoming matters for value, treatment-management agents that chase missing records, negotiation tooling that auto-builds case financials, and litigation modules for discovery drafting and trial-prep document generation.

The case-valuation engine is grounded in Piai, which EvenUp markets as the largest proprietary personal-injury dataset in the industry — 250,000-plus verdicts and settlements used to benchmark a new claim against comparables by injury type, jurisdiction, and venue. That dataset is the moat: general-purpose legal AI tools do not have access to PI-specific outcome data, so their valuation suggestions are educated guesses where EvenUp''s are statistically grounded.

The competitive frame is narrow on purpose. Eve.legal is the closest direct competitor — also AI for plaintiff lawyers, also pushing demand generation and case management — but with a broader plaintiff-litigation framing rather than EvenUp''s laser focus on personal injury. Generalist legal-AI tools (Harvey, Lexis+ AI, Casetext / CoCounsel) do not solve the PI-specific workflow because demand letters, medical-record chronologies, and settlement valuation are not their training emphasis. Inside the PI vertical, EvenUp is the most-funded and most-deployed option, with 2,000-plus PI firms cited as customers.

Pricing is sales-gated and varies by firm size and module set; EvenUp does not publish per-case or per-seat pricing publicly.', 'https://evenuplaw.com', 'paid', '[{"plan":"Firm","price":"Custom","features":["AI demand-package generation","Intake scoring","Treatment management","Negotiation financials"]},{"plan":"Litigation","price":"Custom","features":["Discovery drafting","Medical chronologies","Trial-prep document generation"]},{"plan":"Enterprise","price":"Custom","features":["Multi-office deployment","SSO","Custom integrations","Dedicated success"]}]'::jsonb, 'intermediate', false, '{"web"}', '{"AI demand-package generation in firm''s tone","Medical-record chronology and clinical-narrative extraction","Case valuation grounded in 250K+ verdict / settlement dataset (Piai)","Intake scoring to flag high-value cases","Treatment-management AI agents that chase missing records","AI negotiation financials and damages calculations","Discovery drafting (interrogatories, requests, responses)","Trial-prep document generation including motions","Plaintiff-PI-specific workflow design"}', '{"Filevine","Litify","SmartAdvocate","CASEpeer","Salesforce","Microsoft 365"}', true, '{"Plaintiff personal-injury firms processing 50+ matters/month","PI paralegals drowning in demand-letter backlog","Managing partners who want consistent demand quality across attorneys","Litigation teams needing fast medical chronologies"}', '{"Defense-side firms (product is plaintiff-PI specific)","Non-PI practice areas (corporate, IP, family — wrong vertical)","Solo PI attorneys with very low case volume (ROI thin)"}', 'The clear category leader for plaintiff PI-firm AI in 2026. The Piai valuation dataset is a real moat — generalist legal AI cannot replicate it.', '{}', 'Hallucination risk is acute in personal-injury work — a fabricated medical-record citation or invented case-valuation figure can blow up settlement negotiations or trigger malpractice. Mata v. Avianca made it canonical that "the AI did it" is not a defense, and demand letters that misstate medical findings carry real exposure. Coverage is US-only with state-by-state variation in valuation depth (strongest in CA, TX, FL, NY; thinner in low-volume states). Practice-management integration is best with Filevine and Litify; deeper CRM integrations may need professional services. Pricing is firm-scale; solo PI attorneys with low monthly case volume rarely clear the ROI threshold.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Generate a complete demand package — narrative, chronology, damages, exhibits — in 30 minutes from a folder of medical records.","Score 50 inbound intake calls overnight and surface the three with highest expected value.","Run an AI agent to chase outstanding medical records from 12 providers without human follow-up.","Benchmark a new soft-tissue case against 1,000 comparable verdicts in the same venue."}', 'Sweet spot: a plaintiff PI firm with 15–200 active matters at any time, where demand-letter throughput is the actual bottleneck and the managing partner can see paralegal hours-per-case as a P&L line. EvenUp compresses that hours-per-case number dramatically, and the valuation dataset gives the negotiating attorney a defensible number to anchor settlement talks. The 2,000-firm install base means the product has been hardened against the workflow quirks of real PI practice rather than legal-tech demos.

Failure modes. Treat every demand letter as a first draft — the medical narrative must be lawyer-reviewed before it leaves the building, both for hallucination risk and for tone calibration. Valuation suggestions are statistical comparables, not predictions of your specific jury — over-relying on the number in negotiation is how firms leave money on the table or under-settle. Multi-state firms should pilot per-jurisdiction; demand quality and valuation depth are not uniform across all 50 states.

What to pilot. Pick 20 recently-settled cases where you know the final number and the demand-letter quality cold. Run EvenUp on the same inputs. Compare draft quality, valuation accuracy, and paralegal time saved. If demand quality matches your senior paralegal''s output and time-per-case drops 50%+, the seat math works at most firm sizes; below that, the playbook needs tuning before scaling.', now()),
('Alexi', 'alexi', 'AI legal research and memo drafting purpose-built for litigators.', 'Alexi is a Toronto-founded legal-AI platform focused on the research-and-memo workflow that litigators run dozens of times per matter. You ask a legal question — "in Ontario, what is the standard for striking a pleading as an abuse of process?" — and Alexi returns a structured research memo: applicable law, leading cases with summaries, distinguishing authorities, and an answer-the-question section. Drafting and document-review modules layer on top: compare two shareholder agreements clause by clause, generate hearing-readiness checklists, draft initial litigation correspondence.

Alexi''s core AI pipeline is a research-question pipeline plus memo generator: the question is decomposed, jurisdiction is detected or specified, primary and secondary sources are retrieved, and the model writes a memo that cites only the retrieved authorities. The "active learning" framing means the system improves with use inside a firm''s tenancy — single-tenant private deployment is offered for firms that need it. Independent benchmarking from VALS AI has rated Alexi at the top on legal-AI accuracy in their published evaluations, which the company leans on heavily as a differentiator.

Competitively, Alexi is the pure-play legal-research pick. Lexis+ AI is the incumbent — bigger source corpus, deeper Shepard''s citation validation, broader product surface, but historically more conservative AI features and tied to a Lexis subscription. Casetext CoCounsel (now part of Thomson Reuters) is the other pure-play, deeply integrated into Westlaw, with strong brief-analysis features. Alexi differentiates by being lighter weight, faster to onboard, jurisdictionally strong in Canada (a real gap for Lexis+ AI / Westlaw equivalents historically), and willing to ship single-tenant deployment for risk-averse firms. For US litigators who already have a Lexis or Westlaw subscription, the pitch is "Alexi answers research questions faster and writes the memo — keep your incumbent for citation validation."

Pricing is sales-gated; Alexi runs a guided trial / consultation funnel rather than self-serve checkout.', 'https://www.alexi.com', 'subscription', '[{"plan":"Firm","price":"Custom","features":["Legal research memos","Drafting and document review","iManage integration","Workflow agents"]},{"plan":"Enterprise","price":"Custom","features":["Single-tenant private deployment","SSO","Custom workflows","Dedicated support"]}]'::jsonb, 'intermediate', true, '{"web","api"}', '{"AI legal-research-question pipeline","AI memo drafting with cited authorities","Document review and clause-by-clause comparison","Workflow agents (hearing readiness, discovery, trial readiness)","Active learning that adapts to firm''s style and prior matters","Single-tenant private deployment option","iManage integration","Strong Canadian-jurisdiction coverage alongside US","VALS AI top-rated on legal-AI accuracy"}', '{"iManage","Microsoft 365","NetDocuments"}', true, '{"Litigators running heavy research-and-memo cycles","Mid-size litigation boutiques","Canadian firms underserved by US-first legal AI","Firms that need single-tenant deployment for client confidentiality"}', '{"Solo lawyers with light research volume","Firms entirely committed to Lexis+ AI or Westlaw Precision AI","Non-litigation transactional-only practices (Spellbook / Robin AI fit better)"}', 'The cleanest pure-play legal-research-and-memo AI in 2026 — strongest pick for litigation boutiques that want a focused tool, not another platform.', '{}', 'Hallucination is the catastrophic failure mode in legal research — Mata v. Avianca exists as a permanent reminder that fabricated case citations carry real sanction risk. Alexi grounds outputs in retrieved authorities, but lawyer verification of every cite is non-negotiable. Source corpus is narrower than Lexis or Westlaw, particularly for older or state-trial-court material. Jurisdiction coverage is strongest for Canada and the US; thinner for UK / EU / APAC. Practice-management and CRM integrations are lighter than legacy incumbents — iManage works well, others may need bespoke work.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Draft a 2,000-word legal-research memo on a specific litigation question with cited authorities in 10 minutes.","Compare two versions of a shareholder agreement and surface every material change.","Run a hearing-readiness checklist agent across an entire matter file.","Get a Canadian-jurisdiction memo on a procedural question that US-first tools answer poorly."}', 'Sweet spot: a 5–50-lawyer litigation boutique where associates spend a meaningful slice of their week on research memos, the firm wants AI but does not want to bet on a heavyweight platform play, and a single-tenant deployment is appealing for client-confidentiality reasons. Alexi compresses memo turnaround from a day to under an hour and gives senior litigators a credible draft to mark up rather than a blank page.

Failure modes. Cite-verify every output — the VALS rating is real but it is not zero hallucination, and the cost of one fabricated case getting into a brief is measured in sanctions and reputational damage. Treat Alexi as the first-pass researcher, not the citator. Source-corpus depth on niche or older case law trails Lexis / Westlaw, so it is best paired with an incumbent for Shepard''s / KeyCite-style validation rather than used as a sole-source provider. Model bias toward common-law commercial reasoning means highly specialised areas (admiralty, ITC, niche regulatory) need more verification.

What to pilot. Pick 10 recent research questions where you know the right answer. Run them through Alexi. Score for accuracy of cited authorities, completeness of analysis, and time saved versus the associate''s baseline. Above 80% accuracy with full cite-verification still adding value, the seat math works for any litigation-heavy practice; below that, expand the test set before scaling.', now()),
('Lexis+ AI', 'lexis-ai', 'LexisNexis''s AI-powered legal research, drafting, and summarization layer on the Lexis source corpus.', 'Lexis+ AI (now positioned as Lexis+ with Protégé) is LexisNexis''s generative-AI workflow layer built on top of the full Lexis primary-law and secondary-source corpus. The product spans the three workflows that define modern legal AI: AI legal research grounded in Lexis-authoritative sources with Shepard''s citation validation; AI drafting that generates transactional documents, litigation motions, complaints, and discovery on demand; and AI summarization that condenses uploaded documents and constructs graphical timelines across multi-document matters. Brief Analysis sits inside the same surface — upload a draft brief, get suggested counter-authorities and weakness analysis.

Architecturally, Protégé Legal AI is a multi-model configuration — Lexis routes requests across LLMs from OpenAI, Google, and Anthropic depending on workload, with continuous evaluation and swapping in of new models. Outputs are grounded in the Lexis corpus to mitigate hallucination, and Shepard''s validation runs over generated cite lists. Integrations include DMS-driven document drafting, so attorneys can pull from their own document set rather than only Lexis''s.

The competitive frame is incumbent-vs-incumbent. Westlaw Precision AI (Thomson Reuters, integrating Casetext CoCounsel) is the equivalent product on the other half of the legal-research duopoly, with comparable Brief Analysis, drafting, and summarization features and tight Westlaw / Practical Law / KeyCite integration. The choice between them is mostly the choice between Lexis and Westlaw as a research provider — most firms already have one and stick with the matching AI layer. Against pure-play tools (Alexi, Harvey, Robin AI), Lexis+ AI''s edge is corpus depth and citation validation; the trade-off is that AI feature velocity has historically lagged the startup pure-plays, with Lexis prioritising defensibility and source grounding over feature breadth.

Pricing is sales-gated and varies by organisation size and capability set; Lexis explicitly states pricing is custom and provides no public per-seat number.', 'https://www.lexisnexis.com/en-us/products/lexis-plus-ai.page', 'subscription', '[{"plan":"Lexis+ with Protégé","price":"Custom","features":["AI legal research grounded in Lexis corpus","Shepard''s citation validation","AI drafting (transactional + litigation)","AI summarization and timelines","Brief Analysis"]},{"plan":"Enterprise","price":"Custom","features":["DMS integration","SSO","Multi-office deployment","Custom workflows"]}]'::jsonb, 'intermediate', true, '{"web","api"}', '{"AI legal research grounded in Lexis primary law and secondary sources","Shepard''s citation validation on AI-generated cite lists","AI drafting of transactional documents, motions, complaints, and discovery","Drafting from uploaded documents and DMS sources","AI summarization of legal documents","Graphical multi-document timelines","Brief Analysis with counter-authority suggestion","Multi-model backend (OpenAI, Google, Anthropic) with continuous evaluation","Authoritative-source grounding to reduce hallucination"}', '{"NetDocuments","iManage","Microsoft 365","Lexis primary-law corpus","Shepard''s","OpenAI","Google","Anthropic"}', true, '{"Firms already on Lexis and standardising on a single-vendor research-plus-AI stack","Litigation teams who need Brief Analysis grounded in authoritative sources","Transactional groups drafting from existing DMS templates","Risk-averse firms who want incumbent-grade defensibility"}', '{"Firms standardised on Westlaw (Westlaw Precision AI is the matching product)","Solo practitioners priced out of full Lexis subscriptions","Teams who want bleeding-edge AI features over corpus depth (pure-plays move faster)"}', 'The default AI layer for any firm already on Lexis. Corpus depth and Shepard''s integration are the moat; expect feature velocity to trail startup pure-plays.', '{}', 'Hallucination risk is reduced by source grounding and Shepard''s, but not eliminated — the Mata v. Avianca rule still applies, and lawyers must verify every cite. Useful only with a Lexis subscription as the underlying research foundation, which is itself an enterprise-scale spend. Feature velocity has historically lagged pure-play startups; expect Brief Analysis and drafting capabilities to evolve quarterly rather than weekly. Pricing is sales-gated and out of reach for most solo practitioners. Coverage is strongest in US federal and state law; international jurisdiction depth varies.', '{"OpenAI GPT models","Anthropic Claude","Google Gemini"}', '{"reddit_threads":[]}'::jsonb, '{"Run an AI research query grounded in Lexis primary law with Shepard''s validation in one workflow.","Generate a draft motion to dismiss using Lexis templates plus uploaded matter documents.","Upload an opposing party''s brief and get counter-authority suggestions automatically.","Summarize a 200-page deposition transcript and build a graphical timeline."}', 'Sweet spot: a firm that already pays for Lexis as its primary research provider and wants a single-vendor AI layer with the same defensibility profile as the underlying research product. Lexis+ AI removes the question of "where did this citation come from" — the source grounding plus Shepard''s validation is exactly what risk-management partners want to see in a deployment memo. The multi-model backend means the product benefits from improvements in any of OpenAI, Anthropic, or Google without re-platforming.

Failure modes. Cite-verify every output — source grounding helps, but the Mata v. Avianca standard does not move because the AI is incumbent-grade. Feature velocity lags startup pure-plays by design; if your firm''s evaluation criterion is "newest AI feature," Lexis is not the winner — but if it is "most defensible AI workflow on the broadest authoritative corpus," it usually is. Switching from Westlaw to Lexis (or vice versa) just to get the matching AI layer is almost always a bad trade — pick the AI that matches your existing research provider.

What to pilot. Run 20 representative tasks across the three pillars (research, drafting, summarization) on real recent matter files. Compare against your current Lexis workflow without the AI layer. Time saved per task and cite-accuracy on outputs are the two numbers that matter — above 30% time saved and 95% cite accuracy, the seat math works for most litigation and transactional groups.', now()),
('BriefCatch', 'briefcatch', 'AI legal-writing coach that polishes briefs and motions with sentence-level rewrite suggestions.', 'BriefCatch is a Microsoft Word add-in that operates as an AI-powered legal-writing coach. Where general writing tools flag generic style issues, BriefCatch is purpose-built for legal prose: it surfaces sentence-level rewrite suggestions calibrated to the conventions of brief writing, motions, opinions, and contracts, and pairs each suggestion with the editorial reasoning so associates learn the craft as they edit. The next-generation product layers AI-powered Bluebook citation corrections, expert writing suggestions tied to legal-writing standards rather than generic AI rewrites, and a writing-quality score that lets supervising attorneys benchmark drafts.

The product was founded in 2017 by Ross Guberman — author of Point Made and Point Taken, and one of the most-cited legal-writing authorities working today — which is the editorial moat. The AI is trained against the standards Guberman has documented across decades of analysing the best appellate briefs in the country, not against generic web prose. Customers cite up to roughly 50% reduction in review and editing time on draft briefs and motions.

Competitively, the frame is narrow. Grammarly Business is a horizontal writing assistant; it catches grammar and tone, but does not understand brief structure, citation form, or the difference between persuasive and informational legal writing. WordRake is the closest legal-specific competitor, focused on concision and clarity rewrites; BriefCatch covers concision but adds Bluebook citation work, persuasive-writing scoring, and an explicitly editorial coaching layer informed by Guberman''s research. Inside large firms it is increasingly common to deploy BriefCatch alongside an associate-training program rather than as a pure productivity tool — the explanations are the differentiator.

Pricing is per-seat and is the closest thing to publicly visible pricing in this category — the product runs a free trial and a per-seat subscription with team and enterprise tiers; published numbers fluctuate, so check the BriefCatch site for current per-seat figures rather than relying on third-party quotes.', 'https://briefcatch.com', 'subscription', '[{"plan":"Free Trial","price":"Free","features":["Time-limited trial of all features","Microsoft Word add-in"]},{"plan":"Individual","price":"Per-seat subscription","features":["Sentence-level rewrite suggestions","AI Bluebook citation corrections","Writing-quality score","Editorial explanations"]},{"plan":"Team / Firm","price":"Custom","features":["Multi-seat deployment","Firm-wide rollout","Associate-training integration","Dedicated support"]}]'::jsonb, 'beginner', false, '{"desktop"}', '{"Microsoft Word add-in for lawyers","AI sentence-level rewrite suggestions tuned to legal writing","AI-powered Bluebook citation corrections","Writing-quality score for benchmarking drafts","Editorial reasoning explained for each suggestion","Coaching layer informed by Ross Guberman''s legal-writing research","Reduces brief review and editing time up to ~50%","Self-serve onboarding via free trial","Designed for briefs, motions, opinions, and contracts"}', '{"Microsoft Word","Microsoft 365"}', true, '{"Litigators polishing briefs and motions","Law firms running associate-training programs","Judges and clerks drafting opinions","Government agencies producing legal writing at scale"}', '{"Pure transactional contract teams (Robin AI / Spellbook fit better)","Non-legal writing (Grammarly is the right horizontal pick)","Teams who do not work in Microsoft Word"}', 'The most credible AI writing coach for lawyers — not a generic grammar checker dressed up for legal, but an editorial layer built on real legal-writing research.', '{}', 'Sentence-level rewrite suggestions still occasionally produce stylistically odd output — every suggestion needs lawyer judgment, and Mata v. Avianca-grade hallucination risk is lower than with research tools but not zero on Bluebook citation work. Coverage is US-first with US-style legal writing as the trained baseline; UK / EU drafting conventions are not the focus. Word-only — no Google Docs add-in at parity. Per-seat pricing for solo practitioners can be a hurdle compared to free generic writing tools, though the legal specificity is the value. Practice-management integration is essentially absent — this is a writing tool, not a workflow platform.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Polish a 30-page appellate brief with sentence-level rewrite suggestions in under an hour.","Run AI Bluebook corrections across an associate''s draft before partner review.","Use writing-quality scores to benchmark associate drafts in a training program.","Tighten a 10-page motion''s prose without losing the substantive arguments."}', 'Sweet spot: a litigation-heavy firm or appellate practice where written work product is the primary deliverable and partner review time is the bottleneck. BriefCatch shifts the partner''s role from line-editing prose to evaluating substance — a leverage gain that compounds across every brief and motion the firm produces. The editorial-explanation layer doubles as associate training, which is a second-order benefit most general-purpose writing tools cannot deliver.

Failure modes. The tool is a coach, not an oracle — every rewrite suggestion needs lawyer judgment, and over-applying suggestions can flatten distinctive voice that strong appellate lawyers cultivate intentionally. AI Bluebook corrections still occasionally miss edge cases; treat citation work as assist, not autopilot. Solo practitioners with light brief volume may find generic free tools adequate for their scale, even if the legal specificity is genuinely better.

What to pilot. Pick five recent briefs where you know the partner''s edit history. Run BriefCatch over the same drafts. Compare the rewrite suggestions against the partner''s actual edits. If BriefCatch surfaces 60%+ of the issues the partner caught, the seat math works at any volume above a few briefs per month per attorney; if not, the firm''s house style is far enough from the trained baseline that a customisation conversation with BriefCatch is the right next step.', now()),
('Heidi Health', 'heidi-health', 'AI medical scribe with customizable SOAP-note templates and a global clinician footprint.', 'Heidi Health is an AI medical scribe built around two ideas: (1) the clinician should configure the note template, not the vendor, and (2) the product should work in any clinical setting from family medicine to dentistry to mental health. Open the app, hit record, have the consultation, and Heidi produces a structured note in whichever template — SOAP, SOAPE, problem-oriented, dental, psych, etc. — the clinician has saved. Templates are editable in plain English, which removes the usual rigidity of canned scribe outputs.

The AI stack pairs medical-tuned ASR with an LLM layer that handles note structuring, an "Evidence" feature for guideline-aware research lookups (Research / Treatment / Explain / Compare), and a "Comms" feature for follow-up letters and patient instructions. A 21-gram on-body microphone ("Heidi Remote") extends the product into bedside, ward-round, and home-visit settings where laptops are impractical.

Compared with Suki and Abridge — both heavily focused on US health-system sales — Heidi competes as a lighter-weight, self-serve, globally-available scribe. It is HIPAA, SOC 2, ISO 27001, and GDPR aligned, plus regional certifications for AU, NZ, Canada, and the UK NHS, which is the broadest compliance footprint of any scribe product at this price point.

Sweet spot: solo clinicians, small practices, and global markets that hosted DAX Copilot and Abridge will not reach for years. Adoption is genuinely viral inside Australian and UK primary care.', 'https://heidihealth.com', 'freemium', '[{"plan":"Free","price":"$0","features":["Limited consults / month","Core transcription","Standard templates"]},{"plan":"Pro","price":"Subscription","features":["Unlimited consults","Custom templates","Evidence and Comms features","Priority support"]},{"plan":"Together / Teams","price":"Custom","features":["Multi-clinician workspace","Admin controls","Group billing"]},{"plan":"Enterprise","price":"Custom","features":["SSO","Data residency","BAA / DPA","Dedicated success"]}]'::jsonb, 'beginner', false, '{"web","mobile","desktop"}', '{"AI medical transcription tuned for clinical speech","Customizable SOAP / SOAPE / problem-oriented templates","Evidence module — guideline-aware research lookup","Comms module — follow-up letters and patient instructions","Heidi Remote 21g on-body microphone with offline capture","Specialty coverage: family medicine, mental health, dentistry, allied health, veterinary","Multi-language consult support","Browser, iOS, Android, desktop apps","HIPAA, SOC 2, ISO 27001, GDPR, AU APP, NZ, UK NHS, Canada PIPEDA"}', '{"Vidal Group","HealthPathways","EmGuidance","MIMS","BMJ Group"}', true, '{"Solo GPs and small primary-care practices outside the US","Mental-health and allied-health clinicians who need flexible templates","Clinicians in AU / NZ / UK / Canada where DAX and Abridge are unavailable","Clinicians who want to self-onboard without a 6-month enterprise sale"}', '{"US health systems already standardised on Epic + DAX Copilot","Surgical / procedural specialties where ambient capture is impractical","Clinics requiring deep bidirectional Epic write-back today"}', 'The most globally-accessible AI scribe in 2026. Lighter than Suki / Abridge on enterprise tooling, but the template flexibility and self-serve onboarding make it the right pick for solo clinicians and non-US markets.', '{"https://www.heidihealth.com/help"}', 'Bidirectional EHR write-back is shallower than Abridge / DAX in US settings — most workflows still rely on copy-paste into the EHR. Specialty-terminology accuracy is strong in primary care but variable in sub-specialties (interventional cardiology, oncology) where vocabulary is dense. BAA / DPA negotiation on the Pro tier is template-driven; complex enterprise procurement still requires the Enterprise tier. Multilingual support exists but quality varies — pilot in your specific language before committing.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Generate a structured SOAP note from a 15-minute primary-care consult with zero typing.","Capture a ward round on the Heidi Remote microphone and produce notes per patient afterwards.","Draft a patient follow-up letter and a referral letter from the same recorded consult.","Look up local treatment guidelines mid-consult through the Evidence feature."}', 'Sweet spot: a solo or small-group clinician — especially outside the US — who wants an AI scribe today, on a credit card, without a six-month enterprise procurement. Heidi''s template flexibility and broad compliance footprint mean a GP in Sydney, a psychologist in London, and a dentist in Toronto can all use the same product with appropriate regional certifications.

Failure modes to know about. First, accuracy on dense sub-specialty vocabulary still trails human review — always read the note before signing. Second, EHR write-back depth is the biggest gap vs DAX / Abridge in US health systems; if you live in Epic and need first-class bidirectional integration, this is not yet that product. Third, the free tier is genuinely limited — most working clinicians will outgrow it inside a week and need the Pro tier.

What to pilot. Run Heidi for one full clinic day (15–25 patients). Measure (a) time from consult-end to signed note vs your current workflow, (b) edit volume per note, (c) clinician satisfaction. If you save more than 30 minutes per clinic day and edit fewer than 30% of paragraphs, the ROI is obvious; if either metric misses, the issue is usually template tuning — invest an hour customizing templates before judging.', now()),
('Freed', 'freed-ai', 'Founder-led AI medical scribe priced for individual US clinicians.', 'Freed is an AI medical scribe built specifically for the individual US clinician — not the health system. The pricing surprise of the category lives here: Starter at $39/month, Core at $79/month, Premier at $119/month (or $104/month billed annually). That tier structure is unusual in healthcare AI, where the rest of the market (DAX Copilot, Suki, Abridge) is sold as a six-figure health-system contract with months of procurement. Freed went the other direction and sells per-seat to working clinicians.

The AI does the standard ambient-scribe job — capture the conversation, generate a structured note — but layers on visit preparation, ICD-10 and CPT coding suggestions, patient instructions, referral letters, and one-click EHR transfer. Higher tiers add a clinician AI assistant for decision support and the "Front Desk" AI receptionist for inbound patient communications. The product is HIPAA-compliant and SOC 2 Type II certified; recordings are not stored.

Compared with DAX Copilot (Microsoft Nuance, sold to enterprise) and Suki (also enterprise-leaning, deeper Epic integration), Freed competes by being self-serve, fast to onboard, and priced for a single physician. The trade-off: Freed''s EHR write-back is one-click paste / template insertion rather than the deep bidirectional integration the enterprise tools have spent years building.

The company reports 26,000+ clinicians across 1,300+ clinics and claims 32 million patient visits transcribed in 2025 — credible numbers for a product that was a YC-style startup three years ago. Founder-led culture is a real differentiator: feature requests reach engineering quickly, and the team is publicly visible.', 'https://getfreed.ai', 'subscription', '[{"plan":"Starter","price":"$39/month","features":["Core scribe","Limited templates","Single clinician"]},{"plan":"Core","price":"$79/month","features":["Full templates","ICD-10 / CPT coding","Visit prep","One-click EHR transfer"]},{"plan":"Premier","price":"$119/month ($104/mo annual)","features":["AI clinician assistant","Front Desk AI receptionist","Advanced templates","Priority support"]},{"plan":"Groups","price":"Custom","features":["Multi-clinician","Admin","Group billing","BAA"]}]'::jsonb, 'beginner', false, '{"web","mobile","desktop"}', '{"AI medical scribe — ambient capture and structured note","Visit preparation and patient summaries","ICD-10 and CPT coding suggestions","Patient instructions and referral letter generation","One-click EHR transfer (paste-style)","AI clinician decision-support assistant (Premier)","Front Desk AI receptionist (Premier)","HIPAA + SOC 2 Type II","No patient recording storage"}', '{"Epic (paste workflow)","Athenahealth","eClinicalWorks","Cerner","Practice Fusion"}', true, '{"Solo US clinicians and small private practices","Clinicians frustrated by enterprise procurement timelines","Specialty practices that want a per-seat scribe instead of a system contract"}', '{"Large hospital systems needing deep Epic / Cerner write-back","Non-US clinicians (US-first product)","Clinicians requiring HITRUST certification today"}', 'The clearest-priced, fastest-to-onboard AI scribe in the US in 2026. Per-seat pricing in a category dominated by enterprise sales is the genuine differentiator.', '{"https://www.getfreed.ai/learn"}', 'EHR write-back is paste-style rather than deep bidirectional — workable in Epic but not as smooth as DAX Copilot inside an Epic-standardised health system. Coding suggestions are decision-support, not authoritative — clinicians remain liable for billing accuracy. HITRUST certification is not yet held (SOC 2 Type II is the current bar) — some health systems will require HITRUST. Specialty terminology coverage is strong in primary care and behavioural health; surgical and high-acuity specialty notes still need clinician review. US-only — not built for international privacy regimes.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Generate a complete patient note from a recorded primary-care visit in under a minute.","Get ICD-10 / CPT coding suggestions surfaced alongside the note for billing review.","Auto-draft patient instructions and referral letters from the same encounter.","Run a Front Desk AI receptionist that handles inbound calls and routes them to the correct workflow."}', 'Sweet spot: an individual US clinician — primary care, psychiatry, behavioural health, or a small specialty practice — who wants a working AI scribe by tomorrow on a personal credit card. Freed is the right answer; enterprise alternatives are not built for that buyer.

Failure modes. Coding suggestions look authoritative — they are not. Treat them as draft, validate before submitting claims, and budget time to audit accuracy on your specific specialty mix. EHR write-back is the second pain point: if your health system has banned copy-paste workflows or requires deep bidirectional integration, Freed is the wrong fit and you need DAX or Suki. Third, scaling to a 50+ clinician group raises governance questions (admin, audit logs, RBAC) the product handles less elegantly than enterprise alternatives.

What to pilot. Run Freed for one full clinic week as your only documentation tool. Track (a) minutes per note saved, (b) percent of generated notes you edit substantively, (c) coding-suggestion accuracy on a sample of 20 visits. If two of those three metrics clear your bar, the per-seat math works trivially against a typical specialty fee schedule; if not, the issue is usually template customisation — invest the time before walking away.', now()),
('Augmedix', 'augmedix', 'Ambient AI documentation for hospitals and health systems, with a deeper services layer.', 'Augmedix is one of the older incumbents in ambient clinical documentation — founded in 2012, public until acquired by Commure in 2024, and now an AWS-backed AI documentation provider for hospitals and large health systems. Where Heidi and Freed sell to individual clinicians, Augmedix sells to CMOs and CIOs: enterprise contracts, deep EHR integration, HITRUST certification, and a services layer that combines ambient AI with optional human quality review.

The product line includes Augmedix Go (fully automated ambient AI documentation), Augmedix Live (live human medical scribes augmenting the AI), and Augmedix Notes (specialty-tuned ambient documentation including Emergency Medicine, Oncology, and other high-acuity environments). The architecture handles complex multi-speaker exam-room conversations, noisy environments, and specialty-specific vocabulary that simpler scribes struggle with. Notes are written back into Epic, Athenahealth, Oracle Cerner, Meditech, iKnowMed, eClinicalWorks, and NextGen.

Compared with Microsoft / Nuance DAX Copilot — the obvious enterprise comparable — Augmedix has historically differentiated on the human-in-the-loop services layer (a real medical scribe reviewing AI output for high-acuity specialties) and on its specialty-tuned models for ED and oncology. DAX has the Microsoft / Epic distribution advantage; Augmedix the longer healthcare-services pedigree.

The company reports more than 10 million notes generated since 2013 across customers including Dignity Health Medical Group, Alabama Oncology, and Paradise Medical Group. HITRUST + HIPAA compliance and AWS partnership make it a credible enterprise-procurement choice.', 'https://augmedix.com', 'paid', '[{"plan":"Augmedix Go","price":"Custom","features":["Fully automated ambient AI","EHR integration","Specialty templates"]},{"plan":"Augmedix Live","price":"Custom","features":["AI + human medical scribe review","High-acuity specialty support","SLA"]},{"plan":"Augmedix Notes","price":"Custom","features":["Specialty-tuned ambient (ED, Oncology, etc.)","Multi-EHR write-back","HITRUST + HIPAA + BAA","Enterprise admin"]}]'::jsonb, 'intermediate', true, '{"web","mobile","api"}', '{"Ambient AI documentation pipeline","Human-in-the-loop scribe layer (Augmedix Live)","Specialty-tuned models — Emergency Medicine, Oncology, primary care","Multi-EHR bidirectional integration","Multi-speaker exam-room transcription","Noisy-environment robustness","HITRUST certification + HIPAA + BAA","AWS infrastructure backing","Enterprise admin, RBAC, audit logs"}', '{"Epic","Athenahealth","Oracle Cerner","Meditech","iKnowMed","eClinicalWorks","NextGen","AWS","Commure"}', true, '{"Hospital systems and large multi-specialty groups","High-acuity specialties (Emergency Medicine, Oncology) where note quality is mission-critical","Health systems already on AWS / Commure / Athena ecosystems"}', '{"Solo clinicians and small practices (sales motion is enterprise)","Buyers who need self-serve onboarding (this is months-long procurement)","Non-US health systems (primary footprint is US)"}', 'A serious enterprise-grade ambient documentation platform with a real services layer. Pick it when human-in-the-loop quality and specialty depth matter more than self-serve speed.', '{}', 'Sales cycle is enterprise — months, not minutes. Pricing is opaque and negotiated; expect six-figure annual contracts. Specialty coverage is strong where Augmedix has invested (ED, oncology, primary care) but thinner in lower-volume specialties. Multilingual support is limited compared with global-first products like Heidi. The human-scribe tier (Augmedix Live) introduces a third party into the patient encounter — verify this is acceptable under your BAA and patient-consent posture.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Document a high-acuity ED encounter ambiently with human scribe review for billing-grade accuracy.","Standardise oncology note generation across a multi-site cancer-care network with Epic write-back.","Roll out ambient AI documentation across a 1,000-clinician health system with HITRUST + BAA in place.","Replace traditional offshore scribe vendors with an AI + human hybrid that improves over time."}', 'Sweet spot: a US health system with 200+ clinicians, complex specialty mix, an existing EHR investment in Epic / Cerner / Athena, and a CMO who wants ambient documentation in production within 12 months. Augmedix has done this rollout dozens of times and brings a services posture that pure-software competitors do not.

Failure modes. The biggest is buying enterprise capability you do not need — a 5-clinician practice writing $150k checks for Augmedix when Freed at $79/clinician/month would deliver 80% of the outcome. The second is underestimating change management — ambient documentation is a clinician-behaviour change, not just a software install, and Augmedix''s services layer helps but does not eliminate that work. Third, the human-scribe tier creates a real-time human-in-loop that some patient populations or specialty contexts will object to under consent and privacy norms — confirm before rolling out.

What to pilot. Pick one specialty (often ED or oncology) and 20–30 clinicians for a 90-day pilot. Define success metrics up-front: minutes-saved per shift, note quality vs baseline, clinician NPS, billing accuracy. Augmedix has the data infrastructure to report on all four — use it. If the metrics clear, the system-wide rollout case writes itself; if not, the issue is usually clinician adoption, not product capability, and that is the real pre-purchase question.', now()),
('Corti', 'corti', 'AI for clinical conversations — real-time transcription, decision support, and coding APIs.', 'Corti started in emergency medical dispatch — flagging signs of cardiac arrest in real-time 911 calls — and has broadened into a full clinical-conversation AI platform sold primarily as APIs to healthcare developers, EHR vendors, and health-system platform teams. The pitch is different from the standard ambient-scribe positioning: Corti is the AI layer underneath other people''s products, not a clinician-facing app.

The platform exposes four core APIs. (1) Speech-to-Text tuned for medical conversations and clinical environments, (2) Text Generation that turns clinical data into specialty- and language-specific documentation formats, (3) Medical Coding that produces ICD / CPT / SNOMED codes with supporting evidence and audit trails, and (4) an Agentic Framework for orchestrating clinical workflows. Pricing is usage-based in credits — audio per minute, text per token — with $50 free credits at signup.

Compared with Nuance Dragon Medical (the entrenched dictation platform) and DAX Copilot (the ambient scribe), Corti competes by going the platform-API route: build clinical-grade transcription, decision support, coding, and agentic workflows into your own product without retraining a medical ASR model. The differentiation is real — the dispatch-AI heritage shows up as low-latency real-time advisory capability that batch-oriented scribes do not have.

Compliance footprint is one of the broadest in healthcare AI: HIPAA, GDPR, FedRAMP, SOC 2, ISO 27001, and others. The platform reports 1M+ clinical interactions per week and integrates with major EHRs, practice-management systems, NHS, and Microsoft healthcare partners.', 'https://corti.ai', 'paid', '[{"plan":"Free Credits","price":"$50 credit","features":["Sandbox access","All APIs","Trial-only"]},{"plan":"Usage-based","price":"Per credit (audio minutes / text tokens)","features":["Speech-to-Text API","Text Generation API","Medical Coding API","Agentic Framework"]},{"plan":"Enterprise","price":"Custom","features":["Volume pricing","Data residency","BAA / DPA","SLA","Dedicated support"]}]'::jsonb, 'intermediate', true, '{"api"}', '{"Speech-to-Text API tuned for clinical conversations","Text Generation API for specialty- and language-specific notes","Medical Coding API (ICD / CPT / SNOMED) with audit trail","Agentic Framework for clinical workflows","Real-time advisory (heritage from emergency dispatch)","Multilingual clinical support","HIPAA + GDPR + FedRAMP + SOC 2 + ISO 27001","NHS and Microsoft healthcare partnerships","Usage-based credits pricing"}', '{"Epic","Cerner","Athenahealth","NHS systems","Microsoft Cloud for Healthcare","major practice-management platforms"}', true, '{"Healthcare developers and EHR vendors building clinical AI features","Health-system platform teams who want APIs not a clinician-facing app","Emergency-medicine and dispatch use cases where real-time advisory matters","Companies needing FedRAMP-aligned clinical AI"}', '{"Solo clinicians wanting a turnkey scribe app (use Heidi or Freed)","Buyers who need an end-user product on day one","Teams without engineering to integrate APIs"}', 'The most credible API-first clinical AI platform in 2026. Pick it when you are building healthcare software, not buying a scribe app.', '{}', 'API-first means you need engineering to integrate — there is no end-user product. Coding API outputs are decision-support; final billing-coding accountability remains with the clinician / coder. Specialty-language coverage is broad but quality varies by language pair — pilot your specific languages before committing. Real-time advisory features inherited from the dispatch heritage are powerful but require careful UX work to surface insight without overwhelming clinicians. Pricing in credits is transparent but unpredictable until you have a few weeks of production traffic to model against.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Build a clinical-grade ASR feature into an EHR or PM platform without training your own medical ASR.","Add real-time decision-support advisory to an emergency-dispatch or telehealth product.","Generate specialty-tuned documentation from raw conversation data inside your own clinician-facing app.","Wire ICD / CPT / SNOMED coding with audit trail into a revenue-cycle product."}', 'Sweet spot: a healthcare software team that wants clinical-grade AI primitives without the cost of training and certifying their own. Corti''s heritage in regulated emergency-dispatch use cases means the platform was built compliance-first, which shortens the procurement conversation with hospital CIOs.

Failure modes. The biggest is buying APIs and underestimating the product work — ASR + LLM is not a scribe, and the UX layer between Corti''s APIs and a clinician''s workflow is where most product effort sits. Second, real-time advisory is genuinely powerful but easy to misuse: an alert that fires too often is worse than no alert. Third, multilingual quality is uneven across language pairs — what works in English / Danish (Corti''s home market) may not match in less-resourced languages.

What to pilot. Pick one well-scoped feature in your product (e.g., ambient note generation for one specialty, or real-time triage advisory in one workflow), wire it through Corti, and ship it to 20–50 internal users for 30 days. Measure latency, accuracy on your specialty, clinician trust, and credit consumption per encounter. If the latency and accuracy clear your bar, the credit math is usually fine; if either misses, the issue is upstream of Corti — your audio quality, your prompt structure, or your specialty fit.', now()),
('DeepScribe', 'deepscribe', 'Ambient AI scribe with EHR-aware note structuring for specialty practices.', 'DeepScribe is an ambient AI medical scribe targeting US specialty practices — oncology, cardiology, gastroenterology, neurology, orthopedics, urology — with deeper EHR integration than the self-serve scribe tier and lighter procurement than the full hospital-system platforms. Position-wise it sits between Freed (per-seat, primary-care-friendly) and Augmedix / DAX (enterprise health-system contracts), aimed at the specialty-practice middle market.

The AI does the standard ambient-scribe job and then layers on specialty-aware structuring. SmartPrep generates pre-visit context from prior records. The Customization Studio learns each provider''s note style — phrasing preferences, level of detail, structure — over time. The AI Coding feature produces E/M, ICD-10, and HCC codes with audit-ready documentation. DeepScribe Assist surfaces decision-support insights at the point of care. Notes write back into Epic, Cerner, athenahealth, eClinicalWorks, Flatiron, OnTada, and specialty-specific systems (OMS, MM20).

Compared with Suki (also mid-market, slightly broader specialty footprint) and Abridge (deeper Epic integration but heavier enterprise sales), DeepScribe competes on EHR coverage breadth and specialty depth — particularly in oncology and cardiology where the Flatiron / OnTada integrations matter. The company reports 80% clinician adoption rates inside its specialty customer base, which is a meaningfully high number in a category where pilot-to-rollout drop-off is common.

Compliance is HIPAA + SOC 2 Type II; HITRUST is not yet on the public certification list, which can be a gating question for some larger health systems.', 'https://deepscribe.ai', 'paid', '[{"plan":"Practice","price":"Custom","features":["Ambient AI scribe","EHR integration","Customization Studio"]},{"plan":"Specialty","price":"Custom","features":["Specialty-tuned models","SmartPrep pre-visit","AI Coding (E/M, ICD-10, HCC)","DeepScribe Assist"]},{"plan":"Enterprise","price":"Custom","features":["Multi-site rollout","Admin / RBAC / audit","BAA","SLA","Dedicated success"]}]'::jsonb, 'beginner', true, '{"web","mobile","api"}', '{"Ambient AI scribe with specialty-aware structuring","SmartPrep — pre-visit patient intelligence","Customization Studio — learns provider note style","AI Coding — E/M, ICD-10, HCC with audit trail","DeepScribe Assist — point-of-care decision support","Bidirectional EHR integration (Epic, Cerner, athenahealth, eClinicalWorks)","Specialty-system integrations (Flatiron, OnTada, OMS, MM20)","HIPAA + SOC 2 Type II","Mobile + web capture"}', '{"Epic","Cerner","athenahealth","eClinicalWorks","Flatiron","OnTada","OMS","MM20"}', true, '{"US specialty practices in oncology, cardiology, GI, neurology, orthopedics, urology","Mid-market multi-site groups too small for DAX but too large for per-seat scribes","Practices that need real EHR write-back, not paste-style"}', '{"Solo primary-care clinicians (per-seat alternatives are cheaper)","Health systems requiring HITRUST today","Non-US clinicians (US-first product)"}', 'The strongest specialty-practice ambient scribe in the mid-market. Real EHR write-back and specialty depth set it apart from per-seat alternatives.', '{}', 'HITRUST is not yet certified — some larger health systems will gate procurement on this. Per-clinician pricing is sales-quoted, not published — expect a sales conversation before pricing. EHR write-back depth varies by EHR — Epic and Cerner are best, long-tail systems thinner. AI Coding outputs remain decision-support; clinician + coder remain accountable for billing. Specialty terminology accuracy is strong in DeepScribe''s named specialties; outside that list, performance is less validated. Multilingual support is limited.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Document a complex oncology consult ambiently with Flatiron / OnTada write-back.","Generate E/M, ICD-10, and HCC coding suggestions audit-ready for the billing team.","Tune note style per provider so the AI produces notes the clinician would have written.","Surface decision-support cues at the point of care without breaking flow."}', 'Sweet spot: a specialty practice — oncology, cardiology, GI, neurology, orthopedics, urology — with 20–500 clinicians, on Epic / Cerner / athena / eClinicalWorks, that has outgrown per-seat scribes and is not yet ready (or large enough) for an Augmedix / DAX enterprise rollout. DeepScribe was built for this buyer and the named integrations (Flatiron, OnTada) are unusual differentiation in the category.

Failure modes. The first is HITRUST — if your health system requires it as a gate, factor that into procurement timing. The second is over-relying on AI Coding without a coding QA process — the audit trail is good, but the legal accountability sits with the practice, not DeepScribe. Third, the Customization Studio works well but takes weeks of clinician feedback to converge on per-provider style — budget the change-management time and do not judge accuracy in week one.

What to pilot. Run a 60–90 day pilot with 10–20 clinicians in your highest-volume specialty. Track minutes-saved, edit-volume, coding-suggestion accuracy on a sample, and clinician NPS. Pay specific attention to EHR write-back stability inside your environment — that is the most common operational failure point. If three of those four metrics clear your bar, the rollout case is strong; if EHR write-back fights you, fix that before scaling regardless of how good the notes are.', now()),
('Lindy', 'lindy-ai', 'No-code AI agents that handle real ops — email triage, scheduling, CRM updates, sales prospecting.', 'Lindy is a no-code AI-agent platform aimed at operators who need real work done — not a chatbot, but agents that read inboxes, book meetings, update CRMs, prospect leads, and handle inbound calls. You build a Lindy by picking from prebuilt recipes (the Lindy Society marketplace), connecting your tools (Gmail, Google Calendar, Outlook, iMessage, Slack, HubSpot, Notion, Salesforce), and giving plain-English instructions for when the agent should fire and what it should do.

The platform''s differentiators are around the action surface. Lindy Email triages inboxes, drafts replies in your voice, and routes messages by intent. Lindy Phone picks up calls 24/7 with a human-quality voice, qualifies leads, and books on your calendar — full inbound voice agent. Lindy Society is a community-curated library of agent templates (sales SDR, recruiter sourcer, executive assistant, support triage) you can clone and tune in minutes. The newer "computer use" tier lets agents click around web apps that don''t expose APIs.

Compared with Zapier AI Agents and Make AI Agents — which bolt LLM steps onto deterministic Zap/Scenario flows — Lindy is agent-native. The runtime is built around a long-running agent that decides what to do next, instead of a static flow that calls an LLM at one step. The cost is the same as the benefit: less predictable than a hard-coded Zap, but capable of handling the messy multi-step ops work that breaks deterministic automations.

Lindy sits in the slot between "I want a chatbot" (use ChatGPT) and "I want a custom-coded agent" (use LangGraph). It is the right buy for a small team that wants 5–10 working agents shipped this month without hiring an engineer.', 'https://lindy.ai', 'freemium', '[{"plan":"Free Trial","price":"7 days, no credit card","features":["Full Plus features","All integrations"]},{"plan":"Plus","price":"$49.99/mo","features":["Standard usage","2 inboxes","All recipes"]},{"plan":"Pro","price":"$99.99/mo","features":["3x usage","3 inboxes","Computer use"]},{"plan":"Max","price":"$199.99/mo","features":["7x usage","5 inboxes","Enhanced computer use"]},{"plan":"Enterprise","price":"Custom","features":["SSO","SCIM","Audit logs","Dedicated support","Team AI assistants","HIPAA"]}]'::jsonb, 'beginner', true, '{"web","api"}', '{"Lindy Society — community marketplace of prebuilt agent recipes","Lindy Email — inbox triage and drafting","Lindy Phone — 24/7 inbound voice agent","Computer use for apps without APIs","Trigger-based agent runtime (email, schedule, webhook, voice)","Hundreds of integrations (Gmail, GCal, HubSpot, Salesforce, Slack, Notion)","Custom prompts and tool selection per agent","Human-in-the-loop approval steps","Team workspaces and agent sharing","Voice cloning for outbound calls"}', '{"Gmail","Google Calendar","Outlook","Slack","iMessage","HubSpot","Salesforce","Notion","Pipedrive","Zoom","Calendly","Twilio","OpenAI","Anthropic"}', true, '{"Founders and operators automating their own inbox and calendar","Sales teams running outbound prospecting and inbound triage","Recruiters sourcing and scheduling at volume","Small support teams routing tickets without an engineer"}', '{"Engineers who want full control (use LangGraph or AutoGen)","Workflows that must be 100% deterministic (Zapier is safer)","Compliance-heavy domains needing on-prem (Lindy is cloud-only)"}', 'The clearest no-code agent platform for operators in 2026. If you have one job to automate and you can describe it in English, Lindy ships it faster than anyone else — at the cost of less predictability than a hard-coded flow.', '{"https://www.lindy.ai/learn"}', 'Agent reliability is still <100% on multi-step tasks — expect human-in-the-loop review for anything customer-facing for the first 2–4 weeks. Cost can creep on Pro/Max plans if agents fire on every email; budget the per-task usage. Cloud-only — no on-prem, no VPC option below Enterprise. Default model is GPT-4-class behind the scenes; you do not get fine-grained model choice on lower tiers. Vendor lock-in: agents and recipes are not portable to another platform.', '{"GPT-4-class","Claude 3.5 Sonnet"}', '{"reddit_threads":[]}'::jsonb, '{"Triage a 200-email inbox every morning, draft replies, and surface only the 5 that need a human.","Run a 24/7 inbound voice agent that qualifies leads and books meetings while you sleep.","Source 100 candidates a week from LinkedIn, enrich with email, and queue personalised outreach.","Auto-update HubSpot deal stages and post Slack summaries when calls end."}', 'Sweet spot: a 1–10 person team where the founder is doing ops work that should not be founder-time work. Lindy Phone alone — a 24/7 inbound voice agent that books meetings — replaces a part-time receptionist for $200/month. Lindy Email lets you keep zero-inbox without paying an EA. Operators get the most value, not engineers.

Failure modes to know. Reliability is the honest weakness. Modern agents are great at 8/10 runs and weird at 2/10 — for inbox triage that is fine, for billing or legal it is not. The pricing tiers are usage-metered behind the scenes, so an over-eager trigger can chew through a month''s usage in a week. Debugging is harder than Zapier — when an agent decides to do the wrong thing, you read transcript logs, not flow diagrams.

What to pilot first. Pick one agent recipe from Lindy Society (Lindy Email or a sales SDR recipe), run it on real data for two weeks, and measure error rate, cost, and time saved. If the agent saves you 5+ hours/week and errors are correctable in <5 minutes/day of review, scale to a second agent. If you spend more time fixing it than it saves, stop — the use case isn''t agent-shaped yet.', now()),
('MultiOn', 'multion', 'AI agent that browses the web on your behalf — browser-control agent with API and Chrome extension.', 'MultiOn (now operating as AGI Inc, parent company behind the AGI-0 mobile agent) shipped one of the first widely-used browser-control agent products: an AI that drives a real Chrome browser to complete tasks for you. Tell it "find me a flight to Tokyo under $800 next month" or "renew my Amazon Prime subscription," and the agent navigates, clicks, fills forms, and reports back. Available as both a Chrome extension for end-users and an Agent API for developers wiring browser-agent capability into their own products.

The Agent API is the technically interesting layer. It exposes a hosted browser-control runtime via REST — you POST a task in natural language, get back a session you can stream events from, and receive the final result (or human-handoff request). Compared with running browser-use yourself on your own infrastructure, MultiOn handles the headless-browser fleet, anti-bot mitigation, session persistence, and login state for you.

Versus the open-source browser-use library, MultiOn is the hosted SaaS layer — you trade local control and free-of-cost for someone else managing Playwright clusters and CAPTCHAs. Versus Anthropic''s computer-use API, MultiOn is web-only (no desktop), but came earlier, sits at a higher level of abstraction (task-level rather than action-level), and prices for production use rather than developer experimentation.

The company has been pivoting hard toward the consumer mobile-agent surface (AGI-0 on Android, with Visa/Qualcomm partnerships), so anyone evaluating the developer Agent API for production should confirm current SLA and roadmap directly. The technology is real and works; the question is whether the API is still the company''s priority.', 'https://multion.ai', 'usage-based', '[{"plan":"Free Tier","price":"Limited monthly task quota","features":["Chrome extension","Try the agent on personal tasks"]},{"plan":"Agent API","price":"Usage-based per task / per minute","features":["Programmatic browser-control agent","Session persistence","Login state","Webhooks"]},{"plan":"Enterprise","price":"Custom","features":["Higher concurrency","Dedicated support","SLA"]}]'::jsonb, 'intermediate', true, '{"web","api","mobile"}', '{"Browser-control AI agent that drives real Chrome sessions","Agent API — hosted browser-agent runtime via REST","Chrome extension for end-user web tasks","Session persistence and login state across runs","Anti-bot and CAPTCHA mitigation handled by the hosted layer","Streaming task events and human-handoff hooks","AGI-0 mobile agent (Android, on-device direction)","Natural-language task interface (no flow building)"}', '{"Chrome","OpenAI","Anthropic","Webhooks","REST API","Visa","Qualcomm"}', true, '{"Developers building products that need an agent to use the live web","Founders prototyping web-task automations without running Playwright","Researchers exploring task-level browser-agent capability"}', '{"Teams needing on-prem or self-hosted control (use browser-use)","Workflows where 100% reliability is required (browser agents drift)","Compliance-heavy domains where third-party browser sessions are off-limits"}', 'A pioneering hosted browser-agent SaaS — useful when you don''t want to run Playwright yourself, but the company''s pivot to consumer mobile (AGI-0) means production users should confirm Agent API SLA before deep integration.', '{"https://docs.multion.ai/"}', 'Browser-agent reliability gap is real — multi-step web tasks succeed roughly 60–85% of the time depending on the site, well below human reliability. Cost-per-run can be high for long task chains (each step is a model call plus headless-browser time). Vendor lock-in risk is elevated by the company''s consumer-product pivot — Agent API roadmap is not as clear as it was. Anti-bot detection on hardened sites (Cloudflare, Datadome) still wins sometimes. Default model is a GPT-4-class hosted by the platform; you do not pick the LLM yourself.', '{"GPT-4-class hosted"}', '{"reddit_threads":[]}'::jsonb, '{"Build a price-monitoring agent that logs into 5 vendor portals nightly.","Prototype a personal-shopping agent that compares 3 retailers and checks out.","Automate weekly social-media reporting from dashboards that have no API.","Power a research assistant that browses authenticated sources on the user''s behalf."}', 'Sweet spot: a developer who has identified one or two web tasks where there is no API, where 80% reliability is good enough, and where the cost of running their own browser-agent stack outweighs paying MultiOn per run. The hosted layer is the genuine value — anti-bot mitigation and login-state management are work you would otherwise do yourself.

Failure modes. Agent reliability on long flows is the honest blocker — 6 sequential steps at 85% each is roughly 38% end-to-end success. Plan for retries, human handoff, or hard caps on chain length. Cost runaway on long tasks is the second issue — a 50-step task hitting GPT-4-class on every step adds up fast. The third is strategic: AGI-0 is clearly the company''s consumer focus now, and a developer-facing Agent API can become a second-priority product overnight.

What to pilot. Pick one web task where the alternative is "we built a brittle Playwright script and it breaks weekly." Run it through MultiOn for two weeks against real production targets. Track success rate, cost per run, and how often you intervene. If it beats your script on success rate or eliminates 80% of the maintenance, the math works. If success drops below 70% or per-run cost exceeds the manual labor cost, build it yourself with browser-use instead.', now()),
('Ema', 'ema', 'Universal AI employee for the enterprise — onboarded like a person, not configured like a tool.', 'Ema positions itself as a universal AI employee — a single platform that can take on enterprise roles (sales development, customer support, HR helpdesk, finance ops) by being onboarded the way a human is. Instead of building flow-based automations, the customer hands Ema role-specific knowledge, SOPs, and tool access; Ema stands up persona-based AI employees that execute the role and improve over time.

The technical core is what the company calls the GenerativeWorkflow Engine — a layer that decomposes a role into goals, decisions, tool calls, and handoffs, then executes them across whatever stack the enterprise already runs (Salesforce, ServiceNow, Workday, SAP, internal CRMs, ticketing). Each persona gets a name, a role definition, ownership of specific outcomes, and a measurable contribution — meant to slot into an org chart, not a Zap.

Compared with Sierra (focused tightly on customer-facing voice/chat agents) and traditional staff augmentation (humans, slow to scale), Ema''s pitch is breadth and depth at once: one platform, many roles, faster than hiring and cheaper than BPO at scale. Compared with horizontal agent platforms like Lindy, Ema is enterprise-only — onboarding is consultative, deployment runs through their team, and pricing reflects that.

For Fortune 1000 buyers who have decided AI workers are coming and want a vendor that brings persona, governance, and integration depth in one package — rather than asking the platform team to wire it themselves — Ema is one of the better-funded entrants in the category in 2026.', 'https://ema.co', 'paid', '[{"plan":"Enterprise","price":"Custom — sales-only","features":["Persona-based AI employees (sales, support, ops, HR, finance)","GenerativeWorkflow Engine","Onboarding-style deployment","Enterprise SaaS integrations","SSO, SOC 2, audit logs","Dedicated success engineering","Outcome-based pricing options"]}]'::jsonb, 'intermediate', true, '{"web","api"}', '{"Persona-based AI employees deployed by role","GenerativeWorkflow Engine — goals, decisions, tool calls, handoffs","Enterprise integration depth (Salesforce, ServiceNow, Workday, SAP)","Role-level KPI tracking and reporting","Human-in-the-loop approval and oversight","Onboarding-style deployment by Ema team","SOC 2 / SSO / audit logs / RBAC","Multi-LLM backend selection","Outcome-based contracting available"}', '{"Salesforce","ServiceNow","Workday","SAP","Microsoft 365","Google Workspace","Slack","Zendesk","HubSpot","Snowflake","OpenAI","Anthropic","Azure OpenAI"}', true, '{"Enterprises hiring AI workers as a category, not a tool","Operations leaders replacing BPO seats with persona-based AI employees","CIOs standardising AI-employee governance across functions"}', '{"Solo operators or small teams (use Lindy or Cassidy)","Engineering teams who want to build agents themselves (Ema is buy-not-build)","Companies looking for a quick self-serve trial — Ema is sales-led only"}', 'The most enterprise-shaped AI-employee platform in 2026 — persona model, GenerativeWorkflow Engine, and onboarding-style deployment built for buyers who think in headcount, not workflows. Real cost and real lock-in; expect quarter-long evaluations.', '{}', 'Sales-only — no self-serve trial, evaluation cycles run quarter-long, and pricing only makes sense at enterprise scale. Agent reliability is a real ceiling on the persona promise — Ema can do 85–95% of a role''s tasks well, but the long tail of edge cases still needs humans. Vendor lock-in is significant: the personas, GenerativeWorkflows, and integrations are not portable. Default model selection lives behind a multi-LLM router; if you require a specific model (e.g., self-hosted LLaMA for compliance), confirm support before signing. Enterprise security gates (data residency, SOC 2 scope, customer-managed keys) vary by deployment — confirm in writing.', '{"GPT-4-class","Claude 3.5 Sonnet","Azure OpenAI","customer-selected via router"}', '{"reddit_threads":[]}'::jsonb, '{"Stand up an AI sales-development persona that owns top-of-funnel outreach across Salesforce and HubSpot.","Deploy an AI HR helpdesk persona that handles tier-1 employee questions across Workday and ServiceNow.","Replace BPO support seats with an AI customer-success persona on Zendesk and Slack.","Roll out an AI finance-ops persona that handles AP triage, vendor onboarding, and reporting in SAP."}', 'Sweet spot: a Fortune 1000 buyer who has already decided AI employees are a category they will spend on, has 50+ seats of repetitive role work to redirect, and wants one vendor accountable for outcomes — not a Zapier scaffolding plus three contractors. Ema''s onboarding-style deployment is the differentiator; you''re paying for the change-management as much as the software.

Failure modes. The reliability gap that breaks no-code agents at $50/month also exists at enterprise scale — Ema cannot make a role 100% autonomous, and the 5–15% tail of work is exactly where human review becomes mandatory. Outcome-based contracts sound clean but require careful KPI definition, or you end up arguing about attribution. Sales-led-only means the eval-to-production timeline is measured in quarters, not weeks; if your urgency is higher, an unblocked self-serve platform plus an in-house engineer will ship faster.

What to pilot. Negotiate a paid 90-day pilot on a single role where the success metric is unambiguous (tickets-resolved-without-escalation, meetings-booked-from-cold-outreach, invoices-processed-without-error). Compare Ema''s output to the human or BPO baseline on the same metric. If Ema delivers ≥80% of the human baseline at <50% of fully-loaded cost, expand to a second role; if not, the platform is not yet ready for that specific role and you will burn change-management capital pushing it.', now()),
('Cassidy', 'cassidy-ai', 'Knowledge-base-grounded AI assistants and agents for SMB ops and support teams.', 'Cassidy is an AI-automation platform built around a single insight: most useful AI work for an operations or support team is grounded in the company''s own knowledge — Notion docs, Google Drive folders, Confluence pages, Gmail threads, support tickets. Cassidy syncs that knowledge continuously, then lets you build assistants and agentic workflows that draft replies, qualify leads, summarise meetings, and run multi-system actions on top of it.

The core surface is the assistant builder — pick a knowledge base, write a system prompt, optionally hand the assistant tool access (HubSpot, Salesforce, Zendesk, Gmail, Slack), and deploy via Slack, Microsoft Teams, or a Chrome / Word / Excel / Outlook extension. The Workflows surface adds multi-step automations: triggers, conditional steps, loops, and tool calls — closer to a no-code agent than a Zap. The "Meetings" feature turns conversations into action items wired into the rest of the stack.

Compared with Glean — the gold standard for enterprise knowledge search but priced and shaped for 1,000+ employee orgs — Cassidy is the SMB-and-mid-market answer. Compared with ChatGPT Team — generic chatbot with file uploads, no real action layer — Cassidy actually executes inside your tools. The 20,000+ team count, SOC 2 / GDPR / HIPAA / CASA compliance, and the free Starter tier make it easy to try without procurement.

For a 10–500 person company that wants knowledge-grounded AI ops without an enterprise-platform price tag, Cassidy is one of the most pragmatic choices in 2026.', 'https://cassidyai.com', 'freemium', '[{"plan":"Starter","price":"Free","features":["3 seats","1 workspace","10,000 AI credits/mo","30,000 pages storage"]},{"plan":"Business","price":"Custom — contact sales","features":["Custom seats and workspaces","Custom AI credits","Premium onboarding","Production-grade automations"]},{"plan":"Enterprise","price":"Custom","features":["White-glove setup","Dedicated success manager","Real-time syncing","SSO","Advanced RBAC","Custom support"]}]'::jsonb, 'beginner', true, '{"web","api"}', '{"Continuous-sync knowledge base (Google Drive, SharePoint, OneDrive, Confluence, Notion)","Assistant builder grounded in your knowledge","Agentic workflows with conditional logic and tool calls","Slack and Microsoft Teams deployment","Chrome, Word, Excel, Outlook extensions","Meeting transcription and action extraction","Multi-system actions (Salesforce, HubSpot, Zendesk, Gmail)","SOC 2 Type II / GDPR / HIPAA / CASA","Multi-workspace separation"}', '{"Google Drive","SharePoint","OneDrive","Confluence","Notion","Salesforce","HubSpot","Zendesk","Gmail","Slack","Microsoft Teams","Chrome","Outlook","OpenAI","Anthropic"}', true, '{"SMB and mid-market ops teams grounding AI in their own knowledge","Support teams drafting replies from a docs-backed assistant","Sales teams qualifying inbound and updating CRM in one flow","Internal helpdesks handling tier-1 IT/HR questions"}', '{"Enterprises that already standardised on Glean (overlap is real)","Engineering teams that want code-first agent frameworks (use LangGraph)","Solo users — Starter is generous, but the value is in shared knowledge"}', 'The right knowledge-grounded AI ops platform for 10–500 person companies in 2026. Free tier is genuinely useful; the paid tiers are where the agentic workflow value compounds.', '{"https://docs.cassidyai.com/"}', 'Knowledge sync quality depends on how clean your source material is — messy Drive folders produce messy answers. AI-credit metering means a chatty workflow can blow through monthly credits faster than expected; monitor early. The agentic workflow builder is solid for 5–10 step flows but starts to feel constrained for 30+ step orchestration (use a code-first framework instead). Default model is GPT-4-class behind the scenes; pick a tier that exposes model choice if you have a specific LLM requirement. Vendor lock-in is real — exporting workflows to another platform is a rebuild, not a migration. Enterprise compliance is strong (SOC 2 / HIPAA) but data residency options are not as flexible as deeply enterprise platforms.', '{"GPT-4-class","Claude 3.5 Sonnet"}', '{"reddit_threads":[]}'::jsonb, '{"Build a Slack assistant that answers product questions from Notion + Drive in real time.","Run a workflow that triages inbound support tickets, drafts a reply from your help-center docs, and updates Zendesk.","Auto-summarise weekly meeting transcripts into action items wired to HubSpot tasks.","Power a tier-1 IT helpdesk that resolves password / access questions from your internal wiki."}', 'Sweet spot: a 25–250 person company where the docs are mostly in Notion / Drive / Confluence, the support team is drowning in repetitive questions, and there is no platform team to build a custom RAG chatbot. Cassidy''s free Starter tier lets you prototype the actual assistant in an afternoon, and the path from prototype to production runs through the same UI rather than a rewrite.

Failure modes. Knowledge quality is the hidden tax — Cassidy can only retrieve what is documented, and the more disorganised your Drive is, the more "I don''t know" answers you get. AI-credit metering surprises early-stage teams who underestimate how chatty their assistants are. The Workflow builder is great until you need 30+ steps with complex branching, at which point the visual canvas becomes harder to debug than code. Glean overlap is real for buyers above 1,000 employees — at that scale, search quality and governance depth tilt toward Glean.

What to pilot. Free Starter, ingest your top 5 most-referenced doc folders, build one Slack assistant for the team that asks the most repetitive questions (usually support or HR). Track deflection rate over two weeks — if 40%+ of questions are answered without a human, it is working. If under 20%, your docs need investment before the AI does.', now()),
('Stack AI', 'stack-ai', 'No-code drag-drop agent and workflow builder for enterprise — LLM apps, RAG, and agentic automations.', 'Stack AI is a no-code platform for building LLM apps, RAG pipelines, and agentic workflows on a visual drag-drop canvas — aimed squarely at enterprise teams that want production-grade AI without a platform-engineering build-out. You wire together nodes for LLM calls, retrieval, tool use, branching, loops, and HTTP calls; deploy as a chatbot, an internal app, an API endpoint, or a Slack/Teams integration; and govern usage at the org level.

The platform''s differentiators are around enterprise readiness. SOC 2 / HIPAA / GDPR compliance is in-place, deployment includes multi-tenant cloud, VPC, and on-premises options, and the data-loader library covers the SaaS sources that mid-market and enterprise stacks actually run (Salesforce, SharePoint, Snowflake, Confluence, S3). RAG nodes handle ingestion, chunking, embedding, and retrieval natively, so a typical "chat with our docs" app comes together in an afternoon.

Compared with Dify and Flowise — the open-source no-code LLM builders — Stack AI trades self-host freedom for managed infrastructure plus enterprise compliance. Compared with Relevance AI — strong on agent teams, similar shape — Stack AI''s pitch is more squarely enterprise platform, less squarely "AI workforce" branding. The Free tier (500 runs/month, 2 projects, 1 seat) makes it easy to prototype, and the gap to Enterprise is the headline pricing discontinuity — there is no obvious mid-tier on the public site, so anyone above the Free quota is in a custom-quote conversation.

For a buyer who has already decided they want a managed no-code agent platform with VPC deployment options and a real compliance story, Stack AI is one of the cleanest fits in 2026.', 'https://stack-ai.com', 'freemium', '[{"plan":"Free","price":"$0","features":["500 runs/mo","2 projects","1 seat","Community Discord support"]},{"plan":"Enterprise","price":"Custom","features":["Custom runs and seats","Unlimited projects","All data loaders","Dedicated infrastructure","Solution engineers","On-premises and VPC deployment","SSO","Access control","SOC 2 / HIPAA / GDPR"]}]'::jsonb, 'intermediate', true, '{"web","api"}', '{"Drag-drop visual builder for LLM apps and agents","Native RAG nodes (ingestion, chunking, embedding, retrieval)","Enterprise data loaders (Salesforce, SharePoint, Snowflake, Confluence, S3)","Agentic workflows with branching, loops, and tool use","Multi-tenant cloud, VPC, and on-premises deployment","SSO, RBAC, and access control","SOC 2 Type II, HIPAA, GDPR compliance","API endpoints for every workflow","Slack and Teams integration","Solution-engineering support on Enterprise"}', '{"Salesforce","SharePoint","Snowflake","Confluence","S3","Google Drive","OneDrive","Notion","Slack","Microsoft Teams","OpenAI","Anthropic","Azure OpenAI","Google Vertex","AWS Bedrock"}', true, '{"Enterprise teams wanting a managed no-code agent platform with compliance","Mid-market ops teams building production RAG apps without engineers","Buyers requiring VPC or on-prem deployment of AI workflows"}', '{"Solo developers (open-source Dify or Flowise are cheaper)","Teams committed to code-first agent stacks (use LangGraph)","Companies happy with consumer-grade tools (Cassidy Starter is friendlier)"}', 'The strongest enterprise-shaped no-code agent platform in 2026 — the compliance story and VPC option are why you pay over Dify, and the visual builder is genuinely production-quality.', '{"https://docs.stack-ai.com/"}', 'Pricing discontinuity is a real friction — there is no public mid-tier between Free and Enterprise, so any team that outgrows 500 runs/month enters a sales conversation immediately. Agent reliability is the same gap that affects every platform in this category — multi-step workflows still drift on edge cases, plan for human review. Vendor lock-in is significant: workflows on Stack AI''s canvas don''t export to Dify or Flowise without a rebuild. Default LLM is GPT-4-class via the platform''s router; verify support for your specific model (e.g., on-prem LLaMA, Azure OpenAI deployment) during procurement. On-prem and VPC deployments are real but priced and timelined accordingly — they are not weekend setups.', '{"GPT-4-class","Claude 3.5 Sonnet","Azure OpenAI","Google Vertex","AWS Bedrock"}', '{"reddit_threads":[]}'::jsonb, '{"Ship a SOC 2-compliant ''chat with our docs'' app sourced from SharePoint and Confluence.","Build an agentic workflow that triages inbound emails, drafts replies, and updates Salesforce.","Deploy an internal RAG assistant on VPC for a regulated industry where SaaS is off-limits.","Stand up a customer-facing AI app with API endpoints and rate-limited access control."}', 'Sweet spot: an enterprise or mid-market team that has cleared "we will buy a managed AI platform" and is choosing between Stack AI, Dify Cloud, and Relevance AI. The compliance story (SOC 2 / HIPAA / GDPR), VPC deployment option, and enterprise data-loader coverage are the three things that justify the premium over open-source self-hosting.

Failure modes. The Free-to-Enterprise jump bites teams that want to ramp gradually — there is no $99/month plan to grow into. Agent reliability on long workflows hits the same wall as everywhere else (multi-step accuracy degrades, plan for human review). The visual canvas is fine for 5–20 step workflows but starts to feel like spaghetti on 50+ step agents — at that point a code-first framework would have been a better choice. Lock-in is real: a year of investment in Stack AI workflows is not portable to a competitor without rebuild.

What to pilot. Use the Free tier to ship one production-realistic workflow end-to-end (RAG over real docs, with at least one tool-use step). Time it. Compare against shipping the same thing on Dify Cloud or building it yourself with LangGraph + a managed vector DB. If Stack AI delivers in <50% of the time and the compliance story matters to procurement, the Enterprise quote is justifiable; if the time savings are marginal and you have engineers, an open-source path is cheaper and less locked in.', now()),
('Decagon', 'decagon', 'Engineering-led autonomous AI customer-support agents driving Klarna-style ticket deflection at enterprise scale.', 'Decagon builds autonomous AI agents for customer support, positioning itself as the engineering-led counterweight to Sierra and Ada. The product centers on its in-house reasoning engine — an agent runtime that ingests your help-center, past tickets, and CRM data, learns the policies and tone, then resolves end-customer conversations end-to-end across chat, email, and embedded widgets. Where most "AI customer support" pitches stop at deflecting FAQs, Decagon''s agents take real actions: process refunds, update subscriptions, look up order status, and escalate cleanly when policy requires a human.

The competitive frame is Decagon vs Sierra vs Ada. Sierra leans brand-experience and voice; Ada is the longest-running pure-play with a polished low-code builder. Decagon''s differentiation is engineering depth — APIs, observability, and a posture aimed at companies who want to instrument and iterate on agent behavior the way they would on any other production system. Reference customers include Klarna-tier consumer brands, fintech, and high-volume D2C operators where each percentage point of deflection is a measurable line on the P&L.

Pricing is enterprise sales-gated and predominantly outcome-based: customers pay per resolved conversation rather than per seat or per message. That alignment-of-incentives pitch is genuinely compelling in board decks, but it also means cost variability scales with traffic in ways procurement teams have to model carefully — a viral spike or a botched product launch can produce a Decagon invoice you did not budget for.

Implementation is non-trivial. Expect 4–8 weeks for a real production rollout with measurable deflection: data pipelines from Zendesk/Salesforce/Kustomer, prompt and policy authoring, evaluation harnesses, and the inevitable round of red-team testing before the agent talks to real users. Decagon''s solutions team is competent, but the buyer-side investment in training data quality and human-in-the-loop QA is the single biggest predictor of outcomes.', 'https://decagon.ai', 'paid', '[{"plan":"Enterprise","price":"Custom","features":["Autonomous AI agents across chat, email, and embedded widgets","Outcome-based pricing (per resolved conversation)","CRM and helpdesk integrations (Zendesk, Salesforce, Kustomer, Intercom)","Reasoning engine with policy authoring","Evaluation harness and quality scoring","SOC 2 Type II, enterprise SSO, audit logs","Dedicated solutions architect"]}]'::jsonb, 'advanced', true, '{"web","api"}', '{"Autonomous AI agents (resolve tickets end-to-end)","Reasoning engine grounded in your knowledge base and ticket history","Action-taking via tools (refunds, account updates, lookups)","Multi-channel: chat widget, email, in-app","Policy authoring and guardrails","Evaluation and quality-scoring dashboards","Live agent handoff with full context","Analytics on deflection rate, CSAT, and resolution quality","Outcome-based billing telemetry"}', '{"Zendesk","Salesforce Service Cloud","Kustomer","Intercom","Gladly","Front","Slack","Snowflake"}', true, '{"High-volume consumer brands targeting Klarna-style deflection","Fintech and D2C ops teams measuring cost-per-resolution","CX leaders who can invest in training data quality","Engineering-led support orgs that want APIs and observability"}', '{"Small teams without dedicated CX ops","Heavily regulated industries without a compliance-vetted rollout plan","Companies expecting plug-and-play with zero training-data work"}', 'The engineering-team''s pick in the autonomous-CX category. Outcome-based pricing aligns incentives but demands traffic forecasting; results live or die on the quality of your historical ticket data.', '{}', 'Outcome-based pricing creates real budget volatility — a traffic spike directly inflates your monthly invoice. Quality is gated by training-data hygiene; messy historical tickets produce messy agents. Hallucination risk is non-zero in regulated verticals (finance, health, insurance) and requires human-in-the-loop review tiers. Voice support is lighter than Sierra''s. Multilingual coverage is solid but not as broad as Cognigy''s. Integration depth beyond the top-5 helpdesks varies — confirm your CRM and OMS are first-class before signing.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Deflect 60%+ of tier-1 customer-support tickets across chat and email.","Resolve order-status, refund, and subscription-change requests end-to-end with no human touch.","Escalate complex cases to human agents with full context and a recommended action.","Run weekly evaluation suites to catch regressions before they hit production users."}', 'Sweet spot: a consumer brand or fintech doing 50k+ tickets a month, with clean historical ticket data and a CX leader who treats deflection rate as a first-class metric. Decagon''s engineering depth pays off when you have an internal team that can iterate on policies, evaluate agent behavior, and integrate the agent with your real systems of record. The Klarna-style headlines are real, but they were earned by buyers who invested heavily on their side.

Failure modes to plan for. Outcome-based pricing is honest but volatile — model your worst-month scenario before signing, and negotiate caps. AI customer service can damage brand trust faster than it builds it: a confidently wrong refund denial is worse than a slow human response, so invest in red-teaming and a strong human-handoff path. Regulated industries (banking, health, insurance) need compliance review before any go-live; do not let a vendor pitch skip this. And do not believe the "weeks to deploy" line — plan for at least one full quarter end-to-end.

What to pilot. Pick one channel (usually chat) and one ticket category with clear policies (order status or refund eligibility). Set a 30-day target deflection rate and a CSAT floor. If Decagon clears both with your own data and your policies, expand category by category — never channel by channel without re-validating. Treat the pilot as a software project with eval gates, not a procurement exercise.', now()),
('Sierra', 'sierra', 'Bret Taylor''s conversational AI agents for brand-quality customer experience, voice-first.', 'Sierra is the conversational AI platform from Bret Taylor (ex-Salesforce co-CEO, former Facebook CTO) and Clay Bavor, focused on brand-quality customer experience. The product spans Sierra Agent (the conversational AI that handles end-customer interactions across chat, email, and increasingly voice), Sierra Voice (a voice-first agent runtime built on low-latency speech models), and Sierra''s agent-builder tooling that lets enterprise teams author personas, policies, and procedures with version control, evaluation, and observability built in.

The competitive frame is Sierra vs Decagon vs Salesforce Einstein Agentforce. Decagon is the engineering-led peer; Agentforce is the in-suite incumbent for Salesforce customers. Sierra''s differentiation is brand polish and voice. The agents are tuned for the cadence and persona of premium consumer brands — Sonos, ADT, WeightWatchers, SiriusXM — and Sierra Voice has gained real traction as natural-sounding phone agents become viable in 2025–2026. The bet is that the experience layer (tone, latency, escalation grace) is what separates a CX agent customers tolerate from one they actually prefer.

Pricing is enterprise sales-gated and outcome-aligned, typically per resolved conversation rather than per seat. Sierra''s contracts skew larger than Decagon''s because the buyer is usually a brand-conscious VP of CX or COO, and the implementation includes a meaningful design layer (persona authoring, voice tuning, brand voice review). Expect 6–12 week implementation cycles for production-grade rollouts, with Sierra''s solutions team co-authoring policies alongside the customer''s CX leadership.

Sierra''s post-2024 growth has been notable: multi-billion valuations, an expanding voice product, and reference logos that read like a Wieden+Kennedy brief. The platform is genuinely good. What it is not is cheap, fast to deploy, or appropriate for buyers who want a low-code chatbot — it is positioned for executive-sponsored CX transformations, and pricing reflects that.', 'https://sierra.ai', 'paid', '[{"plan":"Enterprise","price":"Custom","features":["Sierra Agent across chat, email, and voice","Sierra Voice (low-latency natural voice agents)","Outcome-based pricing (per resolved conversation)","Agent builder with persona, policy, and procedure authoring","Evaluation, observability, and version control","CRM and telephony integrations","Brand-voice tuning with Sierra''s solutions team","SOC 2 Type II, HIPAA available, enterprise SSO"]}]'::jsonb, 'advanced', true, '{"web","api"}', '{"Sierra Agent — conversational AI across chat, email, voice","Sierra Voice — natural, low-latency voice agents","Agent Builder for personas, policies, and procedures","Brand-voice and persona tuning","Action-taking via tools and APIs","Evaluation harness with regression detection","Observability dashboards and conversation review","Live agent handoff with full transcript and context","Multilingual support","Telephony integration for inbound and outbound voice"}', '{"Salesforce","Zendesk","Genesys","NICE","Twilio","AWS","Snowflake","Segment","Slack"}', true, '{"Premium consumer brands prioritizing experience quality","Voice-first CX programs (inbound IVR replacement, outbound)","CX leaders with executive sponsorship and budget for transformation","Companies whose brand voice is a core differentiator"}', '{"Small businesses needing a low-code chatbot","Buyers shopping primarily on price","Teams without a clear CX owner to co-author policies"}', 'The premium choice for brand-led CX, and the strongest voice agent on the market right now. Worth its price for executive-sponsored transformations; overkill for anyone shopping a chatbot.', '{}', 'Outcome-based pricing produces month-to-month variance — model traffic spikes carefully. Implementation is hands-on and slow by SaaS standards; this is not a self-serve product. Voice quality is class-leading but still varies across accents, languages, and noisy environments — pilot in your real conditions, not a Sierra demo. Hallucination risk in regulated industries requires the solutions-team-led compliance review; do not assume defaults are safe for finance or health. Integration is rich for Tier-1 CRMs but thinner outside Salesforce, Zendesk, Genesys.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Replace tier-1 IVR with a natural voice agent that handles 50%+ of inbound calls.","Run a brand-aligned chat agent that resolves account, billing, and product questions.","Deploy outbound voice campaigns for renewal, retention, or service-update notifications.","Author and version-control persona / policy changes with a real evaluation harness."}', 'Sweet spot: a premium consumer brand with executive CX sponsorship, a real budget, and a willingness to invest 6–12 weeks in implementation. Sierra''s edge is the experience polish and the voice product — if your brand cannot afford a CX agent that sounds robotic or off-tone, Sierra is the safer pick than cheaper alternatives. The agent builder genuinely supports professional authoring workflows (versioning, evals, observability) that the cheaper end of the market lacks.

Failure modes. Sierra is expensive, and outcome-based pricing means the cost grows with traffic — finance teams need to model peak-season scenarios. Voice agents fail more visibly than chat agents: a hallucinated phone refund is a much worse customer moment than a hallucinated chat reply, so the eval and human-in-the-loop investment is non-negotiable. The implementation cycle is long; if your CX program needs measurable wins inside a quarter, Sierra is probably the wrong tempo. And the brand-quality focus means it under-delivers if you really just want a cheap deflection bot — buy Ada or Intercom Fin instead.

What to pilot. Start with one voice or chat use case where brand voice matters and current automation is failing. Co-author the persona and policies with Sierra''s team. Define resolution rate, CSAT, escalation rate, and a brand-voice qualitative review as the four eval criteria. If you clear all four after 60 days of real traffic, expand. If brand-voice review fails even when metrics pass, you have a tuning problem worth solving before scaling.', now()),
('Moveworks', 'moveworks', 'AI for IT and employee support — now part of ServiceNow as of 2025.', 'Moveworks is the leading AI platform for employee support, automating IT, HR, and internal help-desk requests through a conversational AI Assistant that lives inside Slack, Teams, and the browser. The platform centers on Moveworks'' Reasoning Engine — a multi-step planner that interprets employee requests, retrieves the right knowledge from connected systems, and either resolves the request directly (password resets, group access, PTO balance, software provisioning) or routes it cleanly to the right team. Creator Studio is the authoring layer where IT and ops teams build custom skills, integrations, and workflows without writing low-level prompt code.

The competitive frame is Moveworks vs Glean vs Workato AI. Glean leans heavily into enterprise search and knowledge discovery; Workato AI builds on its automation platform for workflow-style agents. Moveworks'' specific bet is the employee help-desk: ticket deflection, password resets, software access, HR FAQs, IT service requests. It is a narrower scope than Glean''s "AI for work" pitch but deeper in that vertical, with eight years of training data and integrations specifically tuned for the IT/HR support pattern.

In March 2025, ServiceNow announced an agreement to acquire Moveworks for approximately $2.85 billion. By late 2025 the deal had closed and Moveworks now sits inside ServiceNow''s Now Assist portfolio. For ServiceNow customers, that creates a clear consolidation path; for non-ServiceNow shops, it raises legitimate questions about long-term independence, pricing alignment, and whether features will increasingly assume ServiceNow as the system of record. Moveworks'' leadership has publicly committed to multi-ITSM support, but procurement teams should ask hard questions about the 24-month roadmap if they run on Jira Service Management, Freshservice, or a homegrown stack.

Pricing is enterprise sales-gated, typically a fixed annual platform fee plus per-employee tiering, occasionally with outcome-based components for specific automations. Implementation cycles are 8–16 weeks for a meaningful rollout: connecting identity, ITSM, HR systems, building or activating skills, and tuning the assistant against your org''s specific knowledge.', 'https://moveworks.com', 'paid', '[{"plan":"Enterprise","price":"Custom","features":["AI Assistant in Slack, Teams, browser","Reasoning Engine for multi-step employee requests","Creator Studio for custom skills and workflows","Pre-built integrations for ITSM, HRIS, IDP","ServiceNow / Now Assist alignment post-acquisition","Analytics on deflection, MTTR, CSAT","Enterprise SSO, SOC 2 Type II, GDPR"]}]'::jsonb, 'advanced', true, '{"web","api"}', '{"Moveworks AI Assistant in Slack, Teams, and browser","Reasoning Engine (multi-step planning across systems)","Creator Studio for custom skills and workflows","Pre-built skills for IT, HR, finance, facilities","ITSM integrations (ServiceNow, Jira Service Management, Freshservice)","HRIS integrations (Workday, BambooHR, UKG)","IDP / access management (Okta, Azure AD, Active Directory)","Knowledge ingestion across SharePoint, Confluence, Google Drive","Analytics dashboards (deflection, MTTR, CSAT)","Enterprise governance and audit"}', '{"ServiceNow","Jira Service Management","Freshservice","Workday","Okta","Azure AD","Slack","Microsoft Teams","SharePoint","Confluence","Google Workspace"}', true, '{"Mid-to-large enterprises (3,000+ employees) automating IT/HR help-desk","ServiceNow shops looking to consolidate on Now Assist","Companies with high IT ticket volume and standardized identity/HR systems","CIO/CHRO programs measuring ticket deflection and MTTR"}', '{"Small companies under ~1,000 employees (ROI math gets thin)","Customer-facing CX (different problem; pick Decagon, Sierra, Ada)","Orgs without standardized ITSM or identity systems"}', 'Still the leader for AI employee help-desk in 2026. ServiceNow context is the elephant in the room — buy if you are on or moving to ServiceNow; otherwise renegotiate independence guarantees.', '{}', 'Post-ServiceNow acquisition, long-term independence and roadmap alignment for non-ServiceNow ITSMs is a real procurement question — get written commitments. Implementation is heavy: identity, HRIS, ITSM, and knowledge integrations all need to land before deflection numbers move. Quality depends on knowledge hygiene — messy SharePoint and stale Confluence pages produce mediocre answers. Language coverage is strong for global enterprises but varies by skill. Compliance overhead in regulated industries (finance, health, public sector) requires the enterprise tier and a dedicated security review.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Deflect 40-60% of tier-1 IT tickets (password resets, software access, VPN, MFA).","Automate HR FAQs (PTO balance, payroll, benefits enrollment) inside Slack or Teams.","Provision software access and group membership end-to-end through identity integration.","Triage and route complex requests to the right ITSM queue with full context."}', 'Sweet spot: a 5,000+ employee enterprise running ServiceNow (or migrating to it), with a CIO sponsoring an internal-AI program and a clean-ish identity/ITSM stack. The deflection numbers Moveworks publishes are real but earned by buyers who invested in knowledge cleanup and integration depth. ServiceNow alignment post-acquisition is a feature, not a bug, for that buyer profile.

Failure modes. If you are not on ServiceNow and not planning to migrate, the next 24 months of Moveworks roadmap need explicit procurement attention — get commitments in writing about Jira Service Management and Freshservice parity. Knowledge quality dependency is the single biggest predictor of deflection rate; do not skip the SharePoint/Confluence audit. The platform is overkill for sub-1,000-employee companies — the integration cost and minimum contract sizes do not pencil out, and lighter alternatives (Glean, Workato AI, even ServiceNow Now Assist standalone) will deliver more for less.

What to pilot. Pick the three highest-volume IT ticket categories (usually password reset, MFA, and software access) and the three highest-volume HR categories (PTO, payroll, benefits). Run a 60-day pilot inside Slack or Teams with a clear deflection target and a CSAT floor. If both clear, expand. If knowledge-quality issues are blocking deflection, fix the underlying docs before blaming the agent — this is the single most common Moveworks failure mode.', now()),
('Cognigy', 'cognigy', 'Pure-play conversational AI platform for enterprise contact centers — voice and chat at scale.', 'Cognigy is a conversational AI platform built for enterprise contact centers, going head-to-head with Genesys Cloud CX and Five9 in the contact-center-AI category. The product centers on three pillars: Cognigy.AI (the agent runtime and flow builder), Cognigy Voice Gateway (low-latency voice integration with major CCaaS and telephony platforms), and Cognigy Knowledge AI (the RAG and knowledge-retrieval layer that grounds agent answers in your documentation, policies, and ticket history). Together they let enterprise contact centers automate inbound calls, chat, and messaging with a single platform that supports 100+ languages.

The competitive frame is Cognigy vs Genesys Cloud CX vs Five9. Genesys and Five9 are full CCaaS suites where AI is one capability among many; Cognigy is a pure-play conversational AI vendor that integrates into whatever CCaaS or telephony you already run. That positioning matters: enterprises with existing Genesys, NICE, Avaya, or Cisco contact centers can layer Cognigy on top without ripping out their core. The trade-off is that you do operate two vendors instead of one, and the integration story has to hold up under load and during failover.

Cognigy''s strength is voice. The Voice Gateway has matured significantly through 2024–2026, with low-latency speech recognition, natural TTS, barge-in handling, and integrations into the major CCaaS platforms. The Knowledge AI layer added in 2024 closed the RAG gap with Sierra and Decagon for chat. The platform''s flow builder is more visual / less code-first than Decagon''s, which makes it accessible to contact-center ops teams but can feel constraining for engineering-led buyers who want full programmatic control.

Pricing is enterprise sales-gated, typically a platform license plus per-conversation or per-minute usage. Outcome-based components exist but are less central than at Decagon or Sierra. Implementation cycles are 6–12 weeks for production rollouts and require involvement from contact-center ops, telephony, and IT.', 'https://cognigy.com', 'paid', '[{"plan":"Enterprise","price":"Custom","features":["Cognigy.AI agent runtime and flow builder","Cognigy Voice Gateway (low-latency voice across CCaaS)","Cognigy Knowledge AI (RAG over enterprise content)","100+ language support","Pre-built CCaaS integrations (Genesys, NICE, Avaya, Cisco, Amazon Connect)","Per-conversation / per-minute usage pricing","SOC 2 Type II, ISO 27001, GDPR, HIPAA available"]}]'::jsonb, 'advanced', true, '{"web","api"}', '{"Cognigy.AI agent runtime","Visual flow builder for conversational design","Cognigy Voice Gateway (voice agents on CCaaS)","Cognigy Knowledge AI (RAG over docs, policies, tickets)","100+ language support out of the box","Pre-built CCaaS integrations","Live agent handoff with context","Analytics on containment, AHT, CSAT","Enterprise governance, audit, and compliance"}', '{"Genesys Cloud CX","NICE CXone","Avaya","Cisco Webex Contact Center","Amazon Connect","Twilio","Salesforce Service Cloud","Zendesk","ServiceNow","Microsoft Teams"}', true, '{"Enterprises with existing CCaaS (Genesys, NICE, Avaya, Cisco) layering AI on top","Multilingual contact centers","Voice-heavy support operations","Contact-center ops teams who prefer visual flow design"}', '{"Small businesses without a real contact center","Engineering teams wanting full programmatic control (Decagon fits better)","Greenfield CX programs that should buy a unified suite (Genesys, Five9)"}', 'The right pick for enterprises layering AI onto an existing CCaaS, especially voice-heavy ones. Pure-play independence is a feature; integration depth with Genesys/NICE/Avaya is class-leading.', '{}', 'Two-vendor architecture (Cognigy + your CCaaS) means failover, latency, and support boundaries need clear runbooks. Voice quality varies by CCaaS integration and underlying telephony — pilot in your real environment, not a Cognigy demo. Knowledge AI is solid but newer than Cognigy.AI''s flow runtime; complex retrieval scenarios require tuning. Per-minute / per-conversation pricing creates volume sensitivity. Compliance reviews for finance, health, and public sector add weeks to procurement.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Layer AI voice agents on top of Genesys Cloud CX or NICE CXone without replacing the CCaaS.","Automate multilingual chat across 30+ languages with one platform.","Replace tier-1 IVR with a natural voice agent integrated into existing telephony.","Ground agent answers in product docs, policies, and ticket history via Knowledge AI."}', 'Sweet spot: an enterprise contact center already on Genesys, NICE, Avaya, or Cisco that wants AI without ripping out the CCaaS. Cognigy is the cleanest pure-play option for that buyer, with voice integration that has matured into a real differentiator. Multilingual coverage is class-leading, which matters for global ops where Sierra''s English-first focus is a constraint.

Failure modes. Two-vendor architectures mean two support relationships and two failure modes — invest in operational runbooks, especially for voice failover. Visual flow builders accelerate simple cases but become unwieldy for complex multi-step logic; buyers who want a code-first agent platform should compare Decagon. Per-minute pricing creates volume sensitivity that finance teams should model against your busiest historical month, not your average. AI-customer-service brand risk applies here too: a hallucinated voice answer is a worse moment than a hallucinated chat answer.

What to pilot. Pick one high-volume voice intent (order status, account balance, or appointment management) and one chat use case. Integrate against your real CCaaS in a sandbox, not a Cognigy-hosted demo. Measure containment rate, CSAT, average handle time, and escalation quality across 30 days. If voice containment clears 30% with a CSAT floor, you have a viable program; expand language and intent by intent.', now()),
('Ada', 'ada', 'Pure-play autonomous AI customer-service agent — no underlying suite, just resolution.', 'Ada is one of the longest-running pure-play AI customer-service vendors, and in 2026 the platform has fully repositioned around its AI Agent — an autonomous resolution engine grounded in a reasoning layer that decides, mid-conversation, whether to answer, take an action, or escalate. Ada Coach is the in-product authoring and tuning layer where CX teams review agent transcripts, label correct and incorrect resolutions, and feed those signals back into the agent''s policy. The platform spans chat, email, voice, and social channels, with a strong multilingual story (50+ languages) inherited from Ada''s long history with global D2C brands.

The competitive frame is Ada vs Intercom Fin vs Zendesk AI. Intercom Fin is bundled with Intercom''s messaging suite; Zendesk AI is bundled with Zendesk Suite. Ada''s differentiation is being a pure-play — it does not sell you a helpdesk or a messaging platform; it sells you an AI agent that integrates with whichever helpdesk you already run. That makes Ada the right answer for buyers who like their existing Zendesk/Salesforce/Kustomer setup but want a more committed AI agent than the suite incumbent ships. It also means Ada has had to invest harder in the agent itself, because that is the entire product.

Where Ada has historically been strong: low-code authoring, fast time-to-deploy, and broad multilingual coverage. Where the platform has been catching up since 2024: deep autonomous resolution (the same wave that produced Decagon and Sierra) and voice. The 2025 product cycle delivered meaningful upgrades to the reasoning engine and a real voice product, narrowing the gap. The trade-off is still that Ada''s engineering surface (APIs, observability, custom code) is lighter than Decagon''s — Ada optimizes for fast deployment by CX teams, not for engineering-led iteration.

Pricing is enterprise sales-gated, with a mix of platform fees and per-resolution / per-conversation usage. Outcome-based pricing components have grown across 2024–2026 in line with the broader category trend. Implementation cycles are 4–8 weeks for chat-only deployments and 8–12 weeks if voice is in scope.', 'https://ada.cx', 'paid', '[{"plan":"Enterprise","price":"Custom","features":["Ada AI Agent across chat, email, voice, social","Reasoning engine with autonomous resolution","Ada Coach for in-product tuning and review","50+ language support","Helpdesk integrations (Zendesk, Salesforce, Kustomer, Gladly)","Outcome-based pricing components (per resolution / per conversation)","SOC 2 Type II, GDPR, HIPAA available, enterprise SSO"]}]'::jsonb, 'intermediate', true, '{"web","api"}', '{"Ada AI Agent (autonomous resolution)","Reasoning engine grounded in knowledge and ticket history","Ada Coach (transcript review and tuning)","Multi-channel: chat, email, voice, social","50+ language support","Low-code authoring for CX teams","Action-taking via tools and APIs","Live agent handoff with context","Analytics on resolution rate, CSAT, AHT","Enterprise governance and audit"}', '{"Zendesk","Salesforce Service Cloud","Kustomer","Gladly","Front","Intercom","Shopify","Twilio","Slack","Microsoft Teams"}', true, '{"D2C and consumer brands wanting AI without changing helpdesk","CX teams that want to author and tune the agent themselves","Multilingual support orgs (50+ languages out of the box)","Buyers who prefer pure-play AI over suite-bundled AI"}', '{"Engineering-led teams who want deep API and code surface (Decagon fits better)","Buyers who want everything in one suite (Intercom Fin or Zendesk AI fit better)","Voice-first programs at the highest brand-quality bar (Sierra Voice still leads)"}', 'The strongest pure-play AI agent for buyers who want autonomous resolution without changing helpdesks. Lighter on engineering surface than Decagon, broader on languages than Sierra.', '{}', 'Outcome-based pricing components have grown — model per-resolution costs against peak-traffic months. Engineering surface (custom code, deep APIs, observability) is lighter than Decagon — engineering-led teams may outgrow Ada Coach. Voice is real but newer than chat; pilot in your real telephony environment. Hallucination risk in regulated industries (finance, health) requires the enterprise tier and policy review. Integration depth is excellent for top helpdesks but thinner outside Zendesk, Salesforce, Kustomer. Suite-bundled alternatives (Intercom Fin, Zendesk AI) may be cheaper for existing customers of those suites.', '{}', '{"reddit_threads":[]}'::jsonb, '{"Deploy an autonomous chat agent across 30+ languages without replacing your Zendesk.","Use Ada Coach to review transcripts and tune the agent weekly without engineering involvement.","Add voice automation to a CX program that already runs Ada in chat and email.","Resolve account, billing, and order-status requests end-to-end via API integrations."}', 'Sweet spot: a global D2C or consumer brand on Zendesk, Salesforce, or Kustomer with a CX team that wants to own the agent — author it, tune it, review it — without standing up an AI engineering function. Ada Coach genuinely lets non-engineers improve agent quality week over week, and the multilingual coverage is class-leading for that buyer profile. Pure-play independence is the right answer when your helpdesk is already locked in.

Failure modes. The lighter engineering surface that makes Ada accessible to CX teams becomes a constraint for orgs that want to instrument the agent like a production system — Decagon is a better fit there. Outcome-based pricing means traffic spikes hit the invoice; model peak months. Voice is solid but Sierra still leads at the brand-experience top end. And if you are already paying for Intercom Fin or Zendesk AI inside a suite contract, the marginal value of swapping to Ada needs honest math — sometimes the suite incumbent is good enough for tier-1 deflection.

What to pilot. Stand up Ada in chat against your three highest-volume intents in your two top languages. Set 30-day targets for resolution rate and CSAT, and track Ada Coach review velocity (how many transcripts can your CX team realistically tune per week?). If your CX team can sustain the tuning cadence and metrics clear, expand by language and channel. If tuning velocity stalls, the constraint is your CX team, not the platform — fix the staffing model before scaling.', now());
